interface CacheStrategy<K, V> {
  get(key: K): V | undefined;
  set(key: K, value: V): void;
}

class MapCacheStrategy<K, V> implements CacheStrategy<K, V> {
  private cache = new Map<K, V>();

  get(key: K): V | undefined {
    return this.cache.get(key);
  }

  set(key: K, value: V): void {
    this.cache.set(key, value);
  }
}

function memoize<T, R>(fn: (arg: T) => R, cacheStrategy: CacheStrategy<T, R>): (arg: T) => R {
  return (arg: T): R => {
    const cached = cacheStrategy.get(arg);
    if (cached !== undefined) return cached;

    const result = fn(arg);
    cacheStrategy.set(arg, result);
    return result;
  };
}

function fibonacci(n: number, cacheStrategy: CacheStrategy<number, number> = new MapCacheStrategy()): number {
  const memoizedFib = memoize((num: number): number => {
    if (num <= 1) return num;
    return memoizedFib(num - 1) + memoizedFib(num - 2);
  }, cacheStrategy);

  return memoizedFib(n);
}

from enum import Enum, auto
from typing import Callable, Dict, Optional


class TcpState(Enum):
    """TCP connection states as defined in RFC 793."""
    CLOSED = auto()
    LISTEN = auto()
    SYN_SENT = auto()
    SYN_RECEIVED = auto()
    ESTABLISHED = auto()
    FIN_WAIT_1 = auto()
    FIN_WAIT_2 = auto()
    CLOSE_WAIT = auto()
    CLOSING = auto()
    LAST_ACK = auto()
    TIME_WAIT = auto()


class TcpConnection:
    """State machine for TCP connection handling."""

    def __init__(self):
        """Initialize the TCP connection in CLOSED state."""
        self.state = TcpState.CLOSED
        self._create_transition_table()

    def _create_transition_table(self) -> None:
        """Create the state transition table."""
        self.transitions = {
            TcpState.CLOSED: {
                "passive_open": TcpState.LISTEN,
                "active_open": TcpState.SYN_SENT
            },
            TcpState.LISTEN: {
                "rcv_syn": TcpState.SYN_RECEIVED,
                "send_syn": TcpState.SYN_SENT,
                "close": TcpState.CLOSED
            },
            TcpState.SYN_SENT: {
                "rcv_syn": TcpState.SYN_RECEIVED,
                "rcv_syn_ack": TcpState.ESTABLISHED,
                "close": TcpState.CLOSED
            },
            TcpState.SYN_RECEIVED: {
                "rcv_ack": TcpState.ESTABLISHED,
                "close": TcpState.FIN_WAIT_1
            },
            TcpState.ESTABLISHED: {
                "close": TcpState.FIN_WAIT_1,
                "rcv_fin": TcpState.CLOSE_WAIT
            },
            TcpState.FIN_WAIT_1: {
                "rcv_fin": TcpState.CLOSING,
                "rcv_fin_ack": TcpState.TIME_WAIT,
                "rcv_ack": TcpState.FIN_WAIT_2
            },
            TcpState.FIN_WAIT_2: {
                "rcv_fin": TcpState.TIME_WAIT
            },
            TcpState.CLOSE_WAIT: {
                "close": TcpState.LAST_ACK
            },
            TcpState.CLOSING: {
                "rcv_ack": TcpState.TIME_WAIT
            },
            TcpState.LAST_ACK: {
                "rcv_ack": TcpState.CLOSED
            },
            TcpState.TIME_WAIT: {
                "timeout": TcpState.CLOSED
            }
        }

    def process_event(self, event: str) -> str:
        """Process an event and transition to next state if valid."""
        if event not in self.transitions.get(self.state, {}):
            return f"Invalid event {event} for {self.state.name} state"

        old_state = self.state
        self.state = self.transitions[old_state][event]
        return f"Transitioned from {old_state.name} to {self.state.name}"


# Example usage
if __name__ == "__main__":
    conn = TcpConnection()
    print(f"Initial state: {conn.state.name}")

    print(conn.process_event("active_open"))
    print(f"Current state: {conn.state.name}")

    print(conn.process_event("rcv_syn_ack"))
    print(f"Current state: {conn.state.name}")

    print(conn.process_event("close"))
    print(f"Current state: {conn.state.name}")

import sqlite3
from abc import ABC, abstractmethod
from typing import List, Dict, Any


# Observer interface
class Observer(ABC):
    @abstractmethod
    def update(self, stock_symbol: str, price: float) -> None:
        pass


# Subject (Publisher) class
class StockMarket:
    def __init__(self, db_name: str = "stocks.db"):
        self._observers: List[Observer] = []
        self._stock_prices: Dict[str, float] = {}
        self._db_conn = sqlite3.connect(db_name)
        self._setup_database()

    def _setup_database(self) -> None:
        cursor = self._db_conn.cursor()
        cursor.execute("""
            CREATE TABLE IF NOT EXISTS stock_prices (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                symbol TEXT NOT NULL,
                price REAL NOT NULL,
                timestamp DATETIME DEFAULT CURRENT_TIMESTAMP
            )
        """)
        self._db_conn.commit()

    def attach_observer(self, observer: Observer) -> None:
        if observer not in self._observers:
            self._observers.append(observer)

    def detach_observer(self, observer: Observer) -> None:
        if observer in self._observers:
            self._observers.remove(observer)

    def notify_observers(self, stock_symbol: str) -> None:
        price = self._stock_prices[stock_symbol]
        for observer in self._observers:
            observer.update(stock_symbol, price)

    def set_stock_price(self, stock_symbol: str, price: float) -> None:
        self._stock_prices[stock_symbol] = price

        # Use SQL parameterization to prevent injection attacks
        cursor = self._db_conn.cursor()
        cursor.execute(
            "INSERT INTO stock_prices (symbol, price) VALUES (?, ?)",
            (stock_symbol, price)
        )
        self._db_conn.commit()

        # Notify all observers about the price change
        self.notify_observers(stock_symbol)

    def get_stock_price(self, stock_symbol: str) -> float:
        return self._stock_prices.get(stock_symbol, 0.0)

    def get_price_history(self, stock_symbol: str) -> List[Dict[str, Any]]:
        cursor = self._db_conn.cursor()
        cursor.execute(
            "SELECT symbol, price, timestamp FROM stock_prices WHERE symbol = ? ORDER BY timestamp DESC",
            (stock_symbol,)
        )

        result = [
            {"symbol": row[0], "price": row[1], "timestamp": row[2]}
            for row in cursor.fetchall()
        ]
        return result

    def close_connection(self) -> None:
        if self._db_conn:
            self._db_conn.close()


# Concrete Observer: Display Panel
class DisplayPanel(Observer):
    def __init__(self, name: str):
        self.name = name

    def update(self, stock_symbol: str, price: float) -> None:
        print(f"[{self.name}] Display updated: {stock_symbol} is now ${price:.2f}")


# Concrete Observer: Price Alert
class PriceAlert(Observer):
    def __init__(self, threshold: float):
        self.threshold = threshold

    def update(self, stock_symbol: str, price: float) -> None:
        if price > self.threshold:
            print(f"ALERT: {stock_symbol} has exceeded threshold of ${self.threshold:.2f}! Current price: ${price:.2f}")


# Example usage
if __name__ == "__main__":
    # Create the subject (publisher)
    stock_market = StockMarket()

    # Create observers
    display1 = DisplayPanel("Main Dashboard")
    display2 = DisplayPanel("Mobile App")
    alert = PriceAlert(150.00)

    # Register observers
    stock_market.attach_observer(display1)
    stock_market.attach_observer(display2)
    stock_market.attach_observer(alert)

    # Update stock prices (this will trigger notifications)
    stock_market.set_stock_price("AAPL", 142.50)
    stock_market.set_stock_price("GOOGL", 180.75)
    stock_market.set_stock_price("MSFT", 155.25)

    # Detach an observer
    stock_market.detach_observer(display2)
    print("\nAfter detaching Mobile App observer:")

    # Update price again
    stock_market.set_stock_price("AAPL", 152.75)

    # Get price history for a stock
    history = stock_market.get_price_history("AAPL")
    print("\nPrice history for AAPL:")
    for entry in history:
        print(f"{entry['timestamp']}: ${entry['price']:.2f}")

    # Clean up
    stock_market.close_connection()

/**
 * Represents a node in the Trie data structure.
 * Each node contains a map of children nodes and a flag indicating if it's the end of a word.
 */
class TrieNode {
    // Map of characters to child nodes - O(1) lookup time
    children: Map<string, TrieNode>;

    // Flag to mark end of word - O(1) space
    isEndOfWord: boolean;

    /**
     * Initializes a new TrieNode.
     * Time Complexity: O(1)
     * Space Complexity: O(1) initially, grows with insertions
     */
    constructor() {
        this.children = new Map<string, TrieNode>();
        this.isEndOfWord = false;
    }
}

/**
 * Trie data structure implementation optimized for prefix searches and autocomplete functionality.
 * 
 * Overall Space Complexity: O(N*M) where:
 * - N is the number of words
 * - M is the average length of words
 */
class Trie {
    // Root node of the trie - O(1) space
    private root: TrieNode;

    /**
     * Initializes a new Trie with an empty root node.
     * Time Complexity: O(1)
     * Space Complexity: O(1)
     */
    constructor() {
        this.root = new TrieNode();
    }

    /**
     * Inserts a word into the trie.
     * 
     * Time Complexity: O(L) where L is the length of the word
     * Space Complexity: O(L) in worst case if all characters are new
     * 
     * @param word - The word to insert into the trie
     */
    insert(word: string): void {
        // Start traversal from the root node
        let currentNode = this.root;

        // Iterate through each character of the word - O(L) iterations
        for (const char of word) {
            // If character doesn't exist in children, create a new node
            if (!currentNode.children.has(char)) {
                // O(1) map insertion
                currentNode.children.set(char, new TrieNode());
            }

            // Move to the next node - O(1) map lookup
            currentNode = currentNode.children.get(char)!;
        }

        // Mark the end of the word - O(1) operation
        currentNode.isEndOfWord = true;
    }

    /**
     * Searches for a complete word in the trie.
     * 
     * Time Complexity: O(L) where L is the length of the word
     * Space Complexity: O(1) - no extra space needed
     * 
     * @param word - The word to search for
     * @returns True if the word exists in the trie, false otherwise
     */
    search(word: string): boolean {
        // Find the node corresponding to the last character
        const node = this.findNode(word);

        // Return true if node exists and represents end of a word
        return node !== null && node.isEndOfWord;
    }

    /**
     * Checks if any word in the trie starts with the given prefix.
     * 
     * Time Complexity: O(P) where P is the length of the prefix
     * Space Complexity: O(1) - no extra space needed
     * 
     * @param prefix - The prefix to check
     * @returns True if the prefix exists in the trie, false otherwise
     */
    startsWith(prefix: string): boolean {
        // Return true if the prefix node exists
        return this.findNode(prefix) !== null;
    }

    /**
     * Helper method to find the node corresponding to a string.
     * 
     * Time Complexity: O(M) where M is the length of the string
     * Space Complexity: O(1) - no extra space needed
     * 
     * @param str - The string to find in the trie
     * @returns The node corresponding to the last character, or null if not found
     */
    private findNode(str: string): TrieNode | null {
        // Start traversal from root
        let currentNode = this.root;

        // Traverse the trie for each character - O(M) iterations
        for (const char of str) {
            // If character doesn't exist, return null - O(1) map lookup
            if (!currentNode.children.has(char)) {
                return null;
            }

            // Move to the next node - O(1) map lookup
            currentNode = currentNode.children.get(char)!;
        }

        // Return the final node
        return currentNode;
    }

    /**
     * Returns all words in the trie that start with the given prefix.
     * 
     * Time Complexity: O(P + N*L) where:
     *   - P is the length of the prefix (to find the starting node)
     *   - N is the number of matching words
     *   - L is the average length of matching words
     * Space Complexity: O(N*L) for storing results
     * 
     * @param prefix - The prefix to autocomplete
     * @param limit - Maximum number of suggestions to return (default: unlimited)
     * @returns Array of words that start with the prefix
     */
    autocomplete(prefix: string, limit: number = Number.MAX_SAFE_INTEGER): string[] {
        // Find the node corresponding to the prefix - O(P) time
        const startNode = this.findNode(prefix);

        // If prefix doesn't exist, return empty array
        if (startNode === null) {
            return [];
        }

        // Array to store matching words
        const results: string[] = [];

        // Perform depth-first search to collect all words
        this.dfsCollect(startNode, prefix, results, limit);

        return results;
    }

    /**
     * Depth-first search helper to collect all words starting from a node.
     * 
     * Time Complexity: O(N*L) where:
     *   - N is the number of nodes in the subtree
     *   - L is the average word length
     * Space Complexity: O(H) for recursion stack, where H is max depth
     * 
     * @param node - Current node being processed
     * @param currentWord - Current word built so far
     * @param results - Array to store found words
     * @param limit - Maximum number of results to collect
     */
    private dfsCollect(
        node: TrieNode, 
        currentWord: string, 
        results: string[], 
        limit: number
    ): void {
        // If we've reached the limit, stop the search
        if (results.length >= limit) {
            return;
        }

        // If current node represents end of a word, add to results - O(1) operation
        if (node.isEndOfWord) {
            results.push(currentWord);
        }

        // Explore all children in lexicographic order - O(C) iterations where C is child count
        for (const [char, childNode] of node.children.entries()) {
            // Recursive call for each child - builds the word as we go
            this.dfsCollect(childNode, currentWord + char, results, limit);
        }
    }
}

// Example usage
function demonstrateTrie(): void {
    const trie = new Trie();

    // Insert sample words - O(N*L) where N is number of words, L is average length
    const words = ["apple", "application", "app", "banana", "ball", "cat", "car"];
    for (const word of words) {
        trie.insert(word);
    }

    // Test word search
    console.log("Search 'apple':", trie.search("apple"));      // true
    console.log("Search 'app':", trie.search("app"));          // true
    console.log("Search 'orange':", trie.search("orange"));    // false

    // Test prefix check
    console.log("Prefix 'app':", trie.startsWith("app"));      // true
    console.log("Prefix 'ban':", trie.startsWith("ban"));      // true
    console.log("Prefix 'ora':", trie.startsWith("ora"));      // false

    // Test autocomplete
    console.log("Autocomplete 'app':", trie.autocomplete("app"));  // ["app", "apple", "application"]
    console.log("Autocomplete 'ba':", trie.autocomplete("ba"));    // ["ball", "banana"]
    console.log("Autocomplete 'c':", trie.autocomplete("c"));      // ["cat", "car"]
    console.log("Autocomplete 'x':", trie.autocomplete("x"));      // []

    // Test autocomplete with limit
    console.log("Autocomplete 'a' (limit 2):", trie.autocomplete("a", 2));  // ["app", "apple"]
}

// Uncomment to run the example
// demonstrateTrie();

// server.js
const WebSocket = require('ws');

// Strategy interface
class MessageHandler {
  handle(message, sender, wss) {
    throw new Error('handle() must be implemented');
  }
}

// Concrete strategies
class BroadcastHandler extends MessageHandler {
  handle(message, sender, wss) {
    wss.clients.forEach(client => {
      if (client !== sender && client.readyState === WebSocket.OPEN) {
        client.send(message);
      }
    });
  }
}

class EchoHandler extends MessageHandler {
  handle(message, sender, wss) {
    sender.send(`Echo: ${message}`);
  }
}

// Context
class MessageRouter {
  constructor() {
    this.handlers = new Map();
  }

  registerHandler(type, handler) {
    this.handlers.set(type, handler);
  }

  route(type, message, sender, wss) {
    const handler = this.handlers.get(type);
    if (handler) {
      handler.handle(message, sender, wss);
    }
  }
}

// WebSocket server
const wss = new WebSocket.Server({ port: 8080 });
const router = new MessageRouter();

// Register handlers
router.registerHandler('broadcast', new BroadcastHandler());
router.registerHandler('echo', new EchoHandler());

wss.on('connection', (ws) => {
  console.log('Client connected');

  ws.on('message', (data) => {
    try {
      const { type, message } = JSON.parse(data);
      router.route(type, message, ws, wss);
    } catch (e) {
      console.error('Invalid message format');
    }
  });

  ws.on('close', () => {
    console.log('Client disconnected');
  });
});

console.log('WebSocket server started on port 8080');

import numpy as np
from scipy import sparse

def sparse_matrix_multiply(A, B):
    # Convert to sparse format if inputs are dense
    if not sparse.issparse(A):
        A = sparse.csr_matrix(A)
    if not sparse.issparse(B):
        B = sparse.csr_matrix(B)

    # Ensure A is in CSR format and B is in CSC format for optimal multiplication
    if not isinstance(A, sparse.csr_matrix):
        A = A.tocsr()
    if not isinstance(B, sparse.csc_matrix):
        B = B.tocsc()

    # Perform the multiplication using sparse dot product
    return A.dot(B)

