import { Producer, Consumer, KafkaMessage, Kafka, ProducerRecord, TopicPartitionOffset } from 'kafkajs';
import { v4 as uuidv4 } from 'uuid';
import * as os from 'os';
import * as cluster from 'cluster';

// Message interface
interface Message {
  id: string;
  topic: string;
  payload: any;
  timestamp: number;
}

// Single Kafka PubSub instance
class KafkaPubSub {
  private producer: Producer;
  private consumer: Consumer;
  private kafka: Kafka;
  private subscribers: Map<string, Set<Function>>;
  private isConsumerRunning: boolean;
  private clientId: string;

  constructor(brokers: string[] = ['localhost:9092']) {
    this.clientId = `pubsub-${os.hostname()}-${process.pid}-${Date.now()}`;
    this.kafka = new Kafka({
      clientId: this.clientId,
      brokers: brokers,
      retry: {
        initialRetryTime: 100,
        retries: 8
      }
    });

    this.producer = this.kafka.producer({
      allowAutoTopicCreation: true,
      transactionalId: `transactional-${this.clientId}`
    });

    this.consumer = this.kafka.consumer({
      groupId: `group-${uuidv4()}`,
      sessionTimeout: 30000,
      heartbeatInterval: 3000,
      maxBytesPerPartition: 1048576 * 5, // 5MB
      maxWaitTimeInMs: 50
    });

    this.subscribers = new Map();
    this.isConsumerRunning = false;

    this.init();
  }

  private async init(): Promise<void> {
    await this.producer.connect();
    await this.consumer.connect();

    // Handle graceful shutdown
    process.on('SIGTERM', async () => await this.close());
    process.on('SIGINT', async () => await this.close());
  }

  async publish(topic: string, payload: any): Promise<void> {
    const message: Message = {
      id: uuidv4(),
      topic,
      payload,
      timestamp: Date.now()
    };

    const record: ProducerRecord = {
      topic,
      messages: [{ 
        value: JSON.stringify(message),
        key: message.id 
      }]
    };

    try {
      await this.producer.send(record);
    } catch (err) {
      console.error('Failed to publish message:', err);
      throw err;
    }
  }

  async subscribe(topic: string, callback: Function): Promise<void> {
    // Create subscribers set if it doesn't exist
    if (!this.subscribers.has(topic)) {
      this.subscribers.set(topic, new Set());

      // Subscribe consumer to topic
      await this.consumer.subscribe({ topic, fromBeginning: false });

      if (!this.isConsumerRunning) {
        await this.startConsumer();
      }
    }

    // Add callback to subscribers
    this.subscribers.get(topic)!.add(callback);
  }

  async unsubscribe(topic: string, callback: Function): Promise<void> {
    if (this.subscribers.has(topic)) {
      const topicSubscribers = this.subscribers.get(topic)!;
      topicSubscribers.delete(callback);

      if (topicSubscribers.size === 0) {
        // No more subscribers for this topic
        this.subscribers.delete(topic);
        await this.consumer.stop();

        // Get all topics we're still subscribed to
        const remainingTopics = Array.from(this.subscribers.keys());
        if (remainingTopics.length > 0) {
          // Restart consumer with remaining topics
          await this.consumer.subscribe({ topics: remainingTopics });
          await this.startConsumer();
        } else {
          this.isConsumerRunning = false;
        }
      }
    }
  }

  private async startConsumer(): Promise<void> {
    this.isConsumerRunning = true;

    await this.consumer.run({
      partitionsConsumedConcurrently: 10, // Process multiple partitions concurrently
      eachBatchAutoResolve: true,
      eachBatch: async ({ batch, resolveOffset, heartbeat, isRunning, isStale }) => {
        for (let message of batch.messages) {
          if (!isRunning() || isStale()) break;

          try {
            const parsedMessage = JSON.parse(message.value!.toString());
            const topic = parsedMessage.topic;

            // Notify all subscribers
            const subscribers = this.subscribers.get(topic);
            if (subscribers) {
              for (const callback of subscribers) {
                try {
                  await Promise.resolve(callback(parsedMessage));
                } catch (err) {
                  console.error('Error in subscriber callback:', err);
                }
              }
            }

            resolveOffset(message.offset);
            await heartbeat();
          } catch (err) {
            console.error('Error processing message:', err);
          }
        }
      }
    });
  }

  async close(): Promise<void> {
    this.isConsumerRunning = false;
    await this.consumer.disconnect();
    await this.producer.disconnect();
  }
}

// Horizontally scalable PubSub system
class ScalableKafkaPubSub {
  private instances: KafkaPubSub[];
  private nodeCount: number;
  private brokers: string[];

  constructor(brokers: string[] = ['localhost:9092'], nodeCount = 4) {
    this.nodeCount = nodeCount;
    this.brokers = brokers;

    // Create multiple instances for horizontal scaling
    this.instances = Array(nodeCount).fill(null).map(() => new KafkaPubSub(brokers));
  }

  // Shard by topic for horizontal scaling
  private getInstanceForTopic(topic: string): KafkaPubSub {
    const hash = this.hashCode(topic);
    const index = Math.abs(hash % this.nodeCount);
    return this.instances[index];
  }

  private hashCode(str: string): number {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
      hash = ((hash << 5) - hash) + str.charCodeAt(i);
      hash |= 0; // Convert to 32bit integer
    }
    return hash;
  }

  async publish(topic: string, payload: any): Promise<void> {
    return this.getInstanceForTopic(topic).publish(topic, payload);
  }

  async subscribe(topic: string, callback: Function): Promise<void> {
    return this.getInstanceForTopic(topic).subscribe(topic, callback);
  }

  async unsubscribe(topic: string, callback: Function): Promise<void> {
    return this.getInstanceForTopic(topic).unsubscribe(topic, callback);
  }

  async close(): Promise<void> {
    await Promise.all(this.instances.map(instance => instance.close()));
  }
}

// Worker pool for multi-core scaling
class WorkerPool {
  private workerCount: number;
  private pubSub: ScalableKafkaPubSub | null = null;

  constructor(brokers: string[] = ['localhost:9092'], workerCount = os.cpus().length) {
    this.workerCount = workerCount;

    if (cluster.isPrimary) {
      console.log(`Master ${process.pid} is running`);

      // Fork workers
      for (let i = 0; i < this.workerCount; i++) {
        cluster.fork();
      }

      cluster.on('exit', (worker, code, signal) => {
        console.log(`Worker ${worker.process.pid} died. Restarting...`);
        cluster.fork();
      });
    } else {
      // Workers share the Kafka connection
      console.log(`Worker ${process.pid} started`);
      this.pubSub = new ScalableKafkaPubSub(brokers);
    }
  }

  // Methods to be called from the worker processes
  async publish(topic: string, payload: any): Promise<void> {
    if (!this.pubSub) throw new Error('Cannot call publish on master process');
    return this.pubSub.publish(topic, payload);
  }

  async subscribe(topic: string, callback: Function): Promise<void> {
    if (!this.pubSub) throw new Error('Cannot call subscribe on master process');
    return this.pubSub.subscribe(topic, callback);
  }

  async unsubscribe(topic: string, callback: Function): Promise<void> {
    if (!this.pubSub) throw new Error('Cannot call unsubscribe on master process');
    return this.pubSub.unsubscribe(topic, callback);
  }

  async close(): Promise<void> {
    if (this.pubSub) {
      await this.pubSub.close();
    }
  }
}

