#!/usr/bin/env node

const fs = require('fs');
const path = require('path');
const { program } = require('commander');
const sharp = require('sharp');
const cliProgress = require('cli-progress');
const chalk = require('chalk');
const inquirer = require('inquirer');
const glob = require('glob');

program
  .name('image-resizer')
  .description('A tool to resize multiple images at once')
  .version('1.0.0')
  .requiredOption('-i, --input <path>', 'Input directory or glob pattern of images')
  .requiredOption('-o, --output <path>', 'Output directory for resized images')
  .option('-w, --width <number>', 'Target width in pixels')
  .option('-h, --height <number>', 'Target height in pixels')
  .option('-f, --format <format>', 'Output format (jpg, png, webp)', 'jpg')
  .option('-q, --quality <number>', 'Output quality (1-100)', '80')
  .option('--fit <fit>', 'Fit method (cover, contain, fill, inside, outside)', 'cover')
  .option('--no-progress', 'Disable progress bar')
  .parse(process.argv);

const options = program.opts();

async function run() {
  try {
    // Validate input path
    if (!fs.existsSync(path.resolve(options.input))) {
      console.error(chalk.red(`Error: Input path "${options.input}" does not exist`));
      process.exit(1);
    }

    // Validate dimensions
    if (!options.width && !options.height) {
      const answers = await inquirer.prompt([
        {
          type: 'number',
          name: 'width',
          message: 'Enter target width in pixels (leave empty to maintain aspect ratio):',
        },
        {
          type: 'number',
          name: 'height',
          message: 'Enter target height in pixels (leave empty to maintain aspect ratio):',
        }
      ]);

      options.width = answers.width || null;
      options.height = answers.height || null;

      if (!options.width && !options.height) {
        console.error(chalk.red('Error: You must specify at least one dimension (width or height)'));
        process.exit(1);
      }
    }

    // Create output directory if it doesn't exist
    if (!fs.existsSync(options.output)) {
      fs.mkdirSync(options.output, { recursive: true });
    }

    // Find all images
    const files = glob.sync(options.input);

    if (files.length === 0) {
      console.error(chalk.red(`No images found at "${options.input}"`));
      process.exit(1);
    }

    console.log(chalk.blue(`Found ${files.length} image(s). Starting resize operation...`));

    // Setup progress bar
    const progressBar = new cliProgress.SingleBar({
      format: 'Resizing images |' + chalk.cyan('{bar}') + '| {percentage}% | {value}/{total} images',
      barCompleteChar: '\u2588',
      barIncompleteChar: '\u2591',
      hideCursor: true
    }, cliProgress.Presets.shades_classic);

    if (options.progress) {
      progressBar.start(files.length, 0);
    }

    // Process each image
    const results = await Promise.all(files.map(async (file, index) => {
      try {
        const outputFilename = path.join(
          options.output, 
          `${path.basename(file, path.extname(file))}.${options.format}`
        );

        await sharp(file)
          .resize({
            width: options.width ? parseInt(options.width) : null,
            height: options.height ? parseInt(options.height) : null,
            fit: options.fit
          })
          .toFormat(options.format, { quality: parseInt(options.quality) })
          .toFile(outputFilename);

        if (options.progress) {
          progressBar.update(index + 1);
        }

        return { file, success: true };
      } catch (err) {
        return { file, success: false, error: err.message };
      }
    }));

    if (options.progress) {
      progressBar.stop();
    }

    // Report results
    const successful = results.filter(r => r.success).length;
    const failed = results.filter(r => !r.success).length;

    console.log(chalk.green(`\n✓ Successfully resized ${successful} image(s)`));

    if (failed > 0) {
      console.log(chalk.yellow(`⚠ Failed to resize ${failed} image(s):`));
      results.filter(r => !r.success).forEach(result => {
        console.log(chalk.red(`  - ${result.file}: ${result.error}`));
      });
    }

  } catch (err) {
    console.error(chalk.red(`\nError: ${err.message}`));
    process.exit(1);
  }
}

run();

