// Initialize editor
textEditor.focus();

// Detect content changes
textEditor.addEventListener('input', () => {
  isContentModified = true;
  updateStatusBar('Modified');
  updateWordCount();

  // Notify main process of content change for auto-save
  ipcRenderer.send('content-changed', textEditor.value);
});

// Handle file operations from main process
ipcRenderer.on('file-new', () => {
  textEditor.value = '';
  isContentModified = false;
  updateStatusBar('New File');
  updateWordCount();
});

ipcRenderer.on('file-opened', (event, data) => {
  textEditor.value = data.content;
  isContentModified = false;
  updateStatusBar(`Opened: ${data.filePath}`);
  updateWordCount();
});

ipcRenderer.on('save-request', () => {
  ipcRenderer.send('save-content', textEditor.value);
});

ipcRenderer.on('file-saved', (event, data) => {
  if (data.success) {
    isContentModified = false;
    updateStatusBar(`Saved: ${data.filePath}`);
  } else {
    updateStatusBar(`Error: ${data.error}`);
  }
});

// UI button handlers
document.getElementById('newBtn').addEventListener('click', () => {
  if (isContentModified) {
    if (confirm('You have unsaved changes. Create new file anyway?')) {
      ipcRenderer.send('file-new');
    }
  } else {
    ipcRenderer.send('file-new');
  }
});

document.getElementById('openBtn').addEventListener('click', () => {
  if (isContentModified) {
    if (confirm('You have unsaved changes. Open another file anyway?')) {
      ipcRenderer.send('file-open');
    }
  } else {
    ipcRenderer.send('file-open');
  }
});

document.getElementById('saveBtn').addEventListener('click', () => {
  ipcRenderer.send('save-content', textEditor.value);
});

// Helpers
function updateStatusBar(message) {
  statusBar.textContent = message;
  setTimeout(() => {
    if (isContentModified) {
      statusBar.textContent = 'Modified';
    } else {
      statusBar.textContent = 'Ready';
    }
  }, 3000);
}

function updateWordCount() {
  const text = textEditor.value || '';
  const wordCount = text.trim() === '' ? 0 : text.trim().split(/\s+/).length;
  const charCount = text.length;

  wordCountElement.textContent = `Words: ${wordCount}`;
  charCountElement.textContent = `Chars: ${charCount}`;
}

