class TransactionRecord {
  constructor(
    public userId: string,
    public timestamp: Date,
    public action: string,
    public details: string
  ) {}

  toString(): string {
    return `${this.timestamp.toISOString()} - ${this.userId} - ${this.action}: ${this.details}`;
  }
}

class ImmutableLedger {
  private records: TransactionRecord[] = [];
  private readonly logFilePath: string;
  private readonly hashChain: string[] = ['GENESIS_BLOCK'];

  constructor(logFilePath: string = 'transaction_ledger.log') {
    this.logFilePath = logFilePath;
    this.loadExistingRecords();
  }

  private loadExistingRecords(): void {
    try {
      if (fs.existsSync(this.logFilePath)) {
        const content = fs.readFileSync(this.logFilePath, 'utf8');
        const lines = content.split('\n').filter(line => line.trim());

        // Skip the first line which contains the genesis hash
        for (let i = 1; i < lines.length; i++) {
          const [recordJson, recordHash] = lines[i].split('|');
          const recordData = JSON.parse(recordJson);

          const record = new TransactionRecord(
            recordData.userId,
            new Date(recordData.timestamp),
            recordData.action,
            recordData.details
          );

          this.records.push(record);
          this.hashChain.push(recordHash);
        }
      }
    } catch (error) {
      console.error('Failed to load existing records:', error);
      throw new Error('Ledger integrity compromised');
    }
  }

  private calculateRecordHash(record: TransactionRecord, previousHash: string): string {
    const data = JSON.stringify(record) + previousHash;
    return crypto.createHash('sha256').update(data).digest('hex');
  }

  addRecord(userId: string, action: string, details: string): void {
    const timestamp = new Date();
    const record = new TransactionRecord(userId, timestamp, action, details);

    // Calculate hash that includes the previous hash (blockchain-like)
    const previousHash = this.hashChain[this.hashChain.length - 1];
    const currentHash = this.calculateRecordHash(record, previousHash);

    // Store the record and its hash
    this.records.push(record);
    this.hashChain.push(currentHash);

    // Persist to file system
    const recordJson = JSON.stringify(record);
    fs.appendFileSync(this.logFilePath, `${recordJson}|${currentHash}\n`);
  }

  getRecords(userId?: string): TransactionRecord[] {
    if (userId) {
      return this.records.filter(record => record.userId === userId);
    }
    return [...this.records];
  }

  verifyIntegrity(): boolean {
    // Verify the hash chain
    for (let i = 1; i < this.records.length; i++) {
      const record = this.records[i - 1];
      const previousHash = this.hashChain[i - 1];
      const storedHash = this.hashChain[i];
      const calculatedHash = this.calculateRecordHash(record, previousHash);

      if (calculatedHash !== storedHash) {
        return false;
      }
    }
    return true;
  }

  toString(): string {
    return this.records.map(record => record.toString()).join('\n');
  }
}

