    retry_count = 0

    while retry_count < max_retries:
        try:
            conn = connection_pool.getconn()
            if test_conn(conn):
                return conn

            # Connection is not working, try to reset it
            conn.reset()
            if test_conn(conn):
                return conn

            # If reset didn't work, put it back and try another connection
            connection_pool.putconn(conn)
