def get_data():
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 100, type=int)

    cache_key = f"data-{page}-{per_page}"
    cached_data = redis.get(cache_key)

    if cached_data:
        return cached_data, 200, {'Content-Type': 'application/json'}

    pagination = DataSet.query.paginate(page, per_page, error_out=False)
    data = jsonify([{
        'id': item.id,
        'data': item.data
    } for item in pagination.items])

    redis.setex(cache_key, 60, data.get_data())

    return data

@app.route('/stats')
def stats():
    count = redis.get("count")
    if not count:
        count = db.session.query(func.count(DataSet.id)).scalar()
        redis.setex("count", 60, count)
    return jsonify({'total_records': int(count)})

