import * as zxcvbn from 'zxcvbn';
import * as crypto from 'crypto';
import * as argon2 from 'argon2';
import fetch from 'node-fetch';

export class PasswordPolicy {
  async validatePassword(password: string, username: string): Promise<{ valid: boolean; message?: string }> {
    // Check minimum length (NIST recommends at least 8 characters)
    if (password.length < 8) {
      return { valid: false, message: 'Password must be at least 8 characters long' };
    }

    // Check entropy using zxcvbn
    const result = zxcvbn(password, [username]);
    if (result.score < 3) {
      return { valid: false, message: 'Password is too weak. Try a longer, more complex password' };
    }

    // Check if password has been breached
    const isPwned = await this.checkHaveIBeenPwned(password);
    if (isPwned) {
      return { valid: false, message: 'This password has appeared in a data breach. Choose a different password' };
    }

    return { valid: true };
  }

  private async checkHaveIBeenPwned(password: string): Promise<boolean> {
    const sha1 = crypto.createHash('sha1').update(password).digest('hex').toUpperCase();
    const prefix = sha1.slice(0, 5);
    const suffix = sha1.slice(5);

    try {
      const response = await fetch(`https://api.pwnedpasswords.com/range/${prefix}`);
      const text = await response.text();
      const hashes = text.split('\r\n');

      return hashes.some(line => line.startsWith(suffix));
    } catch (error) {
      console.error('Error checking HaveIBeenPwned:', error);
      return false; // Fail open in case API is unavailable
    }
  }

  async hashPassword(password: string): Promise<string> {
    return await argon2.hash(password, {
      type: argon2.argon2id,
      memoryCost: 65536, // 64 MiB
      timeCost: 3,       // 3 iterations
      parallelism: 4     // 4 parallel threads
    });
  }

  async verifyPassword(hash: string, password: string): Promise<boolean> {
    return await argon2.verify(hash, password);
  }
}

class CircuitBreaker {
  private state: 'CLOSED' | 'OPEN' | 'HALF_OPEN' = 'CLOSED';
  private failureCount = 0;
  private successCount = 0;
  private lastFailureTime = 0;
  private readonly failureThreshold: number;
  private readonly resetTimeout: number;
  private readonly successThreshold = 5;
  private readonly maxBackoffTime: number;

  constructor(failureThreshold = 3, resetTimeout = 5000, maxBackoffTime = 60000) {
    this.failureThreshold = failureThreshold;
    this.resetTimeout = resetTimeout;
    this.maxBackoffTime = maxBackoffTime;
  }

  async execute<T>(request: () => Promise<T>): Promise<T> {
    if (this.state === 'OPEN') {
      if (Date.now() - this.lastFailureTime > this.getBackoffTime()) {
        this.state = 'HALF_OPEN';
      } else {
        throw new Error('Circuit breaker is open');
      }
    }

    try {
      const result = await request();
      this.onSuccess();
      return result;
    } catch (error) {
      this.onFailure();
      throw error;
    }
  }

  private onSuccess(): void {
    if (this.state === 'HALF_OPEN') {
      this.successCount++;
      if (this.successCount >= this.successThreshold) {
        this.reset();
      }
    }
  }

  private onFailure(): void {
    this.lastFailureTime = Date.now();

    if (this.state === 'HALF_OPEN') {
      this.state = 'OPEN';
      this.successCount = 0;
      return;
    }

    this.failureCount++;
    if (this.failureCount >= this.failureThreshold) {
      this.state = 'OPEN';
    }
  }

  private getBackoffTime(): number {
    const backoffTime = Math.min(
      this.resetTimeout * Math.pow(2, this.failureCount - this.failureThreshold),
      this.maxBackoffTime
    );
    return backoffTime;
  }

  private reset(): void {
    this.state = 'CLOSED';
    this.failureCount = 0;
    this.successCount = 0;
  }
}

// HTTP service wrapper example
async function httpRequest<T>(url: string, circuitBreaker: CircuitBreaker): Promise<T> {
  return circuitBreaker.execute(async () => {
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`HTTP error: ${response.status}`);
    }
    return await response.json();
  });
}

