import os
import boto3
import google.cloud.storage as gcs
from typing import Union, Optional
from unittest.mock import Mock
from abc import ABC, abstractmethod

class StorageAdapter(ABC):
    @abstractmethod
    def upload(self, file_path: str, bucket: str, object_name: str) -> bool:
        pass

    @abstractmethod
    def download(self, bucket: str, object_name: str, dest_path: str) -> bool:
        pass

    @abstractmethod
    def delete(self, bucket: str, object_name: str) -> bool:
        pass

    @abstractmethod
    def exists(self, bucket: str, object_name: str) -> bool:
        pass

class S3StorageAdapter(StorageAdapter):
    def __init__(self, client: boto3.client):
        self.client = client

    def upload(self, file_path: str, bucket: str, object_name: str) -> bool:
        try:
            self.client.upload_file(file_path, bucket, object_name)
            return True
        except Exception:
            return False

    def download(self, bucket: str, object_name: str, dest_path: str) -> bool:
        try:
            os.makedirs(os.path.dirname(dest_path), exist_ok=True)
            self.client.download_file(bucket, object_name, dest_path)
            return True
        except Exception:
            return False

    def delete(self, bucket: str, object_name: str) -> bool:
        try:
            self.client.delete_object(Bucket=bucket, Key=object_name)
            return True
        except Exception:
            return False

    def exists(self, bucket: str, object_name: str) -> bool:
        try:
            self.client.head_object(Bucket=bucket, Key=object_name)
            return True
        except Exception:
            return False

class GCSStorageAdapter(StorageAdapter):
    def __init__(self, client: gcs.Client):
        self.client = client

    def upload(self, file_path: str, bucket: str, object_name: str) -> bool:
        try:
            bucket_obj = self.client.bucket(bucket)
            blob = bucket_obj.blob(object_name)
            blob.upload_from_filename(file_path)
            return True
        except Exception:
            return False

    def download(self, bucket: str, object_name: str, dest_path: str) -> bool:
        try:
            os.makedirs(os.path.dirname(dest_path), exist_ok=True)
            bucket_obj = self.client.bucket(bucket)
            blob = bucket_obj.blob(object_name)
            blob.download_to_filename(dest_path)
            return True
        except Exception:
            return False

    def delete(self, bucket: str, object_name: str) -> bool:
        try:
            bucket_obj = self.client.bucket(bucket)
            blob = bucket_obj.blob(object_name)
            blob.delete()
            return True
        except Exception:
            return False

    def exists(self, bucket: str, object_name: str) -> bool:
        bucket_obj = self.client.bucket(bucket)
        blob = bucket_obj.blob(object_name)
        return blob.exists()

class LocalStorageAdapter(StorageAdapter):
    def upload(self, file_path: str, bucket: str, object_name: str) -> bool:
        try:
            dest_path = os.path.join(bucket, object_name)
            os.makedirs(os.path.dirname(dest_path), exist_ok=True)
            with open(file_path, 'rb') as src, open(dest_path, 'wb') as dst:
                dst.write(src.read())
            return True
        except Exception:
            return False

    def download(self, bucket: str, object_name: str, dest_path: str) -> bool:
        try:
            src_path = os.path.join(bucket, object_name)
            os.makedirs(os.path.dirname(dest_path), exist_ok=True)
            with open(src_path, 'rb') as src, open(dest_path, 'wb') as dst:
                dst.write(src.read())
            return True
        except Exception:
            return False

    def delete(self, bucket: str, object_name: str) -> bool:
        try:
            os.remove(os.path.join(bucket, object_name))
            return True
        except Exception:
            return False

    def exists(self, bucket: str, object_name: str) -> bool:
        return os.path.exists(os.path.join(bucket, object_name))

class FallbackStorageAdapter(StorageAdapter):
    def __init__(self, primary: StorageAdapter, fallback: StorageAdapter):
        self.primary = primary
        self.fallback = fallback

    def upload(self, file_path: str, bucket: str, object_name: str) -> bool:
        primary_success = self.primary.upload(file_path, bucket, object_name)
        if primary_success:
            return True
        return self.fallback.upload(file_path, bucket, object_name)

    def download(self, bucket: str, object_name: str, dest_path: str) -> bool:
        primary_success = self.primary.download(bucket, object_name, dest_path)
        if primary_success:
            return True
        return self.fallback.download(bucket, object_name, dest_path)

    def delete(self, bucket: str, object_name: str) -> bool:
        primary_success = self.primary.delete(bucket, object_name)
        fallback_success = self.fallback.delete(bucket, object_name)
        return primary_success and fallback_success

    def exists(self, bucket: str, object_name: str) -> bool:
        return self.primary.exists(bucket, object_name) or self.fallback.exists(bucket, object_name)

class StorageService:
    def __init__(self, storage_adapter: StorageAdapter):
        self.adapter = storage_adapter

    def upload(self, file_path: str, bucket: str, object_name: str) -> bool:
        return self.adapter.upload(file_path, bucket, object_name)

    def download(self, bucket: str, object_name: str, dest_path: str) -> bool:
        return self.adapter.download(bucket, object_name, dest_path)

    def delete(self, bucket: str, object_name: str) -> bool:
        return self.adapter.delete(bucket, object_name)

    def exists(self, bucket: str, object_name: str) -> bool:
        return self.adapter.exists(bucket, object_name)

# Dependency injection
def get_storage_adapter(provider: str, client=None, fallback: bool = False) -> StorageAdapter:
    if provider == 's3':
        s3_client = client if client else boto3.client('s3')
        adapter = S3StorageAdapter(s3_client)
    elif provider == 'gcs':
        gcs_client = client if client else gcs.Client()
        adapter = GCSStorageAdapter(gcs_client)
    elif provider == 'local':
        adapter = LocalStorageAdapter()
    else:
        raise ValueError("Unsupported storage provider")

    if fallback and provider != 'local':
        return FallbackStorageAdapter(adapter, LocalStorageAdapter())

    return adapter

