        if key in self.schema:
            try:
                if self.schema[key]['type'] == 'int':
                    value = int(value)
                    if 'range' in self.schema[key]:
                        min_val, max_val = self.schema[key]['range']
                        if not (min_val <= value <= max_val):
                            raise ValueError(f"Value must be between {min_val} and {max_val}")
                elif self.schema[key]['type'] == 'bool':
                    value = value.lower() in ("true", "yes", "y", "1")
                elif self.schema[key]['type'] == 'choice' and value not in self.schema[key]['choices']:
                    raise ValueError(f"Value must be one of: {', '.join(self.schema[key]['choices'])}")

                self.config[key] = value
                self.save_history()
                return True
            except ValueError as e:
                print(f"Error: {e}")
                return False
        return False

    def undo(self):
        if self.history_index > 0:
            self.history_index -= 1
            self.config = self.history[self.history_index].copy()
