            return True
        print(colored("Cannot undo: No more history", "red"))
        return False

    def redo(self):
        if self.history_index < len(self.history) - 1:
            self.history_index += 1
            self.config = self.history[self.history_index].copy()
            print(colored("↪ Redo: Restored configuration", "yellow"))
            return True
        print(colored("Cannot redo: No more history", "red"))
        return False

