# Abstract base class for the processing stages
class Handler(ABC):
    def __init__(self):
        self._next_handler = None

    def set_next(self, handler: 'Handler') -> 'Handler':
        self._next_handler = handler
        return handler

    @abstractmethod
    def handle(self, request: Any) -> Any:
        pass

# Concrete handlers implementing atomic operations
class DataLoadHandler(Handler):
    def handle(self, data: Dict) -> Dict:
        print("Loading data")
        result = data.copy()
        result["raw_data"] = "Loaded data"

