MAX_RETRIES = 3

class ChunkedUploadManager:
    def __init__(self):
        self.uploads = {}
        os.makedirs(UPLOAD_DIR, exist_ok=True)

    def start_upload(self, token, filename, total_size, chunk_size):
        upload_id = hashlib.md5(f"{token}:{filename}".encode()).hexdigest()

        if upload_id in self.uploads:
            return upload_id, False

        metadata_path = os.path.join(UPLOAD_DIR, f"{upload_id}.json")
        if os.path.exists(metadata_path):
            with open(metadata_path, 'r') as f:
                self.uploads[upload_id] = json.load(f)
            return upload_id, False

        num_chunks = (total_size + chunk_size - 1) // chunk_size

        self.uploads[upload_id] = {
            'id': upload_id,
            'token': token,
            'filename': secure_filename(filename),
            'total_size': total_size,
            'chunk_size': chunk_size,
            'chunks': [{'index': i, 'uploaded': False} for i in range(num_chunks)],
            'completed': False,
            's3_upload_id': None,
            'md5': hashlib.md5()
        }

        self._save_metadata(upload_id)
        return upload_id, True

    def upload_chunk(self, upload_id, chunk_index, chunk_data):
        if upload_id not in self.uploads:
            return False, "Upload not found"

        upload = self.uploads[upload_id]

        if chunk_index >= len(upload['chunks']):
            return False, "Invalid chunk index"

        chunk = upload['chunks'][chunk_index]
        if chunk['uploaded']:
            return True, "Chunk already uploaded"

        for attempt in range(MAX_RETRIES):
            try:
                # Store locally
                chunk_path = os.path.join(UPLOAD_DIR, f"{upload_id}_{chunk_index}")
                with open(chunk_path, 'wb') as f:
                    f.write(chunk_data)

                # Update MD5
                upload['md5'].update(chunk_data)

                # If using S3
                if BUCKET_NAME:
                    if not upload['s3_upload_id']:
                        resp = s3.create_multipart_upload(
                            Bucket=BUCKET_NAME,
                            Key=upload['filename']
                        )
                        upload['s3_upload_id'] = resp['UploadId']

                    resp = s3.upload_part(
                        Bucket=BUCKET_NAME,
                        Key=upload['filename'],
                        PartNumber=chunk_index + 1,
                        UploadId=upload['s3_upload_id'],
                        Body=chunk_data
                    )

                    chunk['etag'] = resp['ETag']

                chunk['uploaded'] = True
                self._save_metadata(upload_id)
                return True, "Chunk uploaded successfully"

            except Exception as e:
                if attempt == MAX_RETRIES - 1:
                    return False, f"Failed after {MAX_RETRIES} attempts: {str(e)}"
                time.sleep(2 ** attempt)  # Exponential backoff

    def complete_upload(self, upload_id, client_md5=None):
        if upload_id not in self.uploads:
            return False, "Upload not found"

        upload = self.uploads[upload_id]

        # Check if all chunks are uploaded
        if not all(chunk['uploaded'] for chunk in upload['chunks']):
            return False, "Not all chunks uploaded"

        # Verify checksum if provided
        if client_md5 and upload['md5'].hexdigest() != client_md5:
            return False, "Checksum verification failed"

        try:
            if BUCKET_NAME and upload['s3_upload_id']:
                # Complete S3 multipart upload
                parts = [
                    {'ETag': chunk['etag'], 'PartNumber': i+1}
                    for i, chunk in enumerate(upload['chunks'])
                ]

                s3.complete_multipart_upload(
                    Bucket=BUCKET_NAME,
                    Key=upload['filename'],
                    UploadId=upload['s3_upload_id'],
                    MultipartUpload={'Parts': parts}
                )
            else:
                # Local file assembly with atomic write
                temp_file = os.path.join(UPLOAD_DIR, f"{upload_id}_complete.tmp")
                final_file = os.path.join(UPLOAD_DIR, upload['filename'])

                with open(temp_file, 'wb') as out_file:
                    for i in range(len(upload['chunks'])):
                        chunk_path = os.path.join(UPLOAD_DIR, f"{upload_id}_{i}")
                        with open(chunk_path, 'rb') as in_file:
                            out_file.write(in_file.read())

                os.rename(temp_file, final_file)

            upload['completed'] = True
            self._save_metadata(upload_id)

            # Clean up chunk files
            self._cleanup(upload_id)

            return True, {
                'filename': upload['filename'],
                'size': upload['total_size'],
                'md5': upload['md5'].hexdigest()
            }

        except Exception as e:
            return False, f"Error completing upload: {str(e)}"

    def _save_metadata(self, upload_id):
        metadata = dict(self.uploads[upload_id])
        metadata['md5'] = metadata['md5'].hexdigest() if metadata['md5'] else None

        with open(os.path.join(UPLOAD_DIR, f"{upload_id}.json"), 'w') as f:
            json.dump(metadata, f)

    def _cleanup(self, upload_id):
        if upload_id not in self.uploads:
            return

        upload = self.uploads[upload_id]

        # Remove chunk files
        for i in range(len(upload['chunks'])):
            chunk_path = os.path.join(UPLOAD_DIR, f"{upload_id}_{i}")
            if os.path.exists(chunk_path):
                os.remove(chunk_path)

        # Keep metadata for idempotency
        del self.uploads[upload_id]

