from abc import ABC, abstractmethod
import os
import json
import hashlib
import pickle
import functools
import requests

class GeocodingService(ABC):
    @abstractmethod
    def get_coordinates(self, address):
        """Convert address to coordinates"""
        pass

    @abstractmethod
    def get_address(self, lat, lng):
        """Convert coordinates to address"""
        pass

# Implement Mapbox service adapter
class MapboxAdapter(GeocodingService):
    def __init__(self, access_token):
        self.base_url = 'https://api.mapbox.com/geocoding/v5/mapbox.places'
        self.access_token = access_token

    def get_coordinates(self, address):
        response = requests.get(f'{self.base_url}/{address}.json', params={'access_token': self.access_token})
        response.raise_for_status()
        coordinates = response.json()['features'][0]['geometry']['coordinates']
        return coordinates  # [lng, lat]

    def get_address(self, lat, lng):
        response = requests.get(f'{self.base_url}/{lng},{lat}.json', params={'access_token': self.access_token})
        response.raise_for_status()
        address = response.json()['features'][0]['place_name']
        return address

# Implement Google Maps service adapter
class GoogleMapsAdapter(GeocodingService):
    def __init__(self, api_key):
        self.base_url = 'https://maps.googleapis.com/maps/api/geocode/json'
        self.api_key = api_key

    def get_coordinates(self, address):
        response = requests.get(self.base_url, params={'address': address, 'key': self.api_key})
        response.raise_for_status()
        coordinates = response.json()['results'][0]['geometry']['location']
        return [coordinates['lng'], coordinates['lat']]  # [lng, lat] to match Mapbox format

    def get_address(self, lat, lng):
        response = requests.get(self.base_url, params={'latlng': f'{lat},{lng}', 'key': self.api_key})
        response.raise_for_status()
        address = response.json()['results'][0]['formatted_address']
        return address

# Implement Mock adapter for testing
class MockAdapter(GeocodingService):
    def __init__(self, mock_data=None):
        self.mock_data = mock_data or {
            'coordinates': {},
            'addresses': {}
        }

    def get_coordinates(self, address):
        return self.mock_data['coordinates'].get(address)

    def get_address(self, lat, lng):
        coord_key = f"{lat},{lng}"
        return self.mock_data['addresses'].get(coord_key)

# Implement caching decorator
def cache(func):
    @functools.wraps(func)
    def wrapper_decorator(*args, **kwargs):
        # Ensure cache directory exists
        os.makedirs('cache', exist_ok=True)

        # Create hash from function arguments (skip self)
        cache_key = hashlib.md5(pickle.dumps((args[1:], kwargs))).hexdigest()
        cache_file = f'cache/{cache_key}.pkl'

        try:
            with open(cache_file, 'rb') as f:
                result = pickle.load(f)
        except (FileNotFoundError, EOFError):
            result = func(*args, **kwargs)
            with open(cache_file, 'wb') as f:
                pickle.dump(result, f)
        return result
    return wrapper_decorator

# Apply caching to service adapters
class CachedGeocodingService(GeocodingService):
    def __init__(self, service):
        self.service = service

    @cache
    def get_coordinates(self, address):
        return self.service.get_coordinates(address)

    @cache
    def get_address(self, lat, lng):
        return self.service.get_address(lat, lng)

# Factory function for dependency injection
def setup_geocoding_service(provider_type, api_key):
    """
    Factory function to create geocoding service with specified provider

    Args:
        provider_type (str): 'mapbox', 'google', or 'mock'
        api_key (str): API key for the service or mock data for mock provider

    Returns:
        CachedGeocodingService: Geocoding service with caching
    """
    if provider_type == 'mapbox':
        service = MapboxAdapter(api_key)
    elif provider_type == 'google':
        service = GoogleMapsAdapter(api_key)
    elif provider_type == 'mock':
        service = MockAdapter(api_key)  # In mock case, api_key is mock data
    else:
        raise ValueError(f'Unsupported provider type: {provider_type}')

    return CachedGeocodingService(service)

