import { execSync } from 'child_process';
import * as fs from 'fs';

// Specification interface
interface Specification<T> {
  isSatisfiedBy(candidate: T): boolean;
  and(other: Specification<T>): Specification<T>;
  or(other: Specification<T>): Specification<T>;
  not(): Specification<T>;
}

// Abstract specification with default implementations
abstract class AbstractSpecification<T> implements Specification<T> {
  abstract isSatisfiedBy(candidate: T): boolean;

  and(other: Specification<T>): Specification<T> {
    return new AndSpecification<T>(this, other);
  }

  or(other: Specification<T>): Specification<T> {
    return new OrSpecification<T>(this, other);
  }

  not(): Specification<T> {
    return new NotSpecification<T>(this);
  }
}

// Composite specifications
class AndSpecification<T> extends AbstractSpecification<T> {
  private readonly left: Specification<T>;
  private readonly right: Specification<T>;

  constructor(left: Specification<T>, right: Specification<T>) {
    super();
    // Deep copy for immutability
    this.left = Object.freeze(structuredClone(left));
    this.right = Object.freeze(structuredClone(right));
  }

  isSatisfiedBy(candidate: T): boolean {
    return this.left.isSatisfiedBy(candidate) && this.right.isSatisfiedBy(candidate);
  }
}

class OrSpecification<T> extends AbstractSpecification<T> {
  private readonly left: Specification<T>;
  private readonly right: Specification<T>;

  constructor(left: Specification<T>, right: Specification<T>) {
    super();
    // Deep copy for immutability
    this.left = Object.freeze(structuredClone(left));
    this.right = Object.freeze(structuredClone(right));
  }

  isSatisfiedBy(candidate: T): boolean {
    return this.left.isSatisfiedBy(candidate) || this.right.isSatisfiedBy(candidate);
  }
}

class NotSpecification<T> extends AbstractSpecification<T> {
  private readonly specification: Specification<T>;

  constructor(specification: Specification<T>) {
    super();
    // Deep copy for immutability
    this.specification = Object.freeze(structuredClone(specification));
  }

  isSatisfiedBy(candidate: T): boolean {
    return !this.specification.isSatisfiedBy(candidate);
  }
}

// Business rule specification
class BusinessRuleSpecification<T> extends AbstractSpecification<T> {
  private readonly rule: (candidate: T) => boolean;
  public readonly name: string;
  public readonly description: string;

  constructor(rule: (candidate: T) => boolean, name: string, description: string) {
    super();
    this.rule = rule;
    this.name = name;
    this.description = description;
    // Freeze the instance for immutability
    Object.freeze(this);
  }

  isSatisfiedBy(candidate: T): boolean {
    return this.rule(candidate);
  }
}

// Rule result with action
interface RuleResult<T> {
  readonly specification: Specification<T>;
  readonly action: (candidate: T) => T;
  readonly name: string;
}

// Rule visualizer using Graphviz
class RuleVisualizer<T> {
  private idCounter = 0;
  private nodes: Map<string, number> = new Map();
  private edges: Array<[number, number, string]> = [];

  generateId(specType: string, specName?: string): number {
    const key = specName ? `${specType}:${specName}` : specType;
    if (!this.nodes.has(key)) {
      this.nodes.set(key, ++this.idCounter);
    }
    return this.nodes.get(key)!;
  }

  buildGraph(spec: Specification<T>): string {
    const dot = ['digraph BusinessRules {', 'rankdir=TB;', 'node [shape=box];'];

    // Reset for new graph
    this.idCounter = 0;
    this.nodes.clear();
    this.edges = [];

    this.traverseSpecification(spec);

    // Add nodes
    for (const [key, id] of this.nodes.entries()) {
      const [type, name] = key.split(':');
      const label = name || type;
      dot.push(`  ${id} [label="${label}"];`);
    }

    // Add edges
    for (const [from, to, label] of this.edges) {
      dot.push(`  ${from} -> ${to} [label="${label}"];`);
    }

    dot.push('}');
    return dot.join('\n');
  }

  private traverseSpecification(spec: Specification<T>, parentId?: number): void {
    let id: number;
    let specType: string;

    if (spec instanceof BusinessRuleSpecification) {
      specType = 'Rule';
      id = this.generateId(specType, (spec as BusinessRuleSpecification<T>).name);
    } else if (spec instanceof AndSpecification) {
      specType = 'AND';
      id = this.generateId(specType);
      this.traverseCompositeSpec(spec as any, id, 'left', 'right');
    } else if (spec instanceof OrSpecification) {
      specType = 'OR';
      id = this.generateId(specType);
      this.traverseCompositeSpec(spec as any, id, 'left', 'right');
    } else if (spec instanceof NotSpecification) {
      specType = 'NOT';
      id = this.generateId(specType);
      const innerSpec = (spec as any).specification;
      const innerSpecId = this.traverseSpecification(innerSpec);
      if (innerSpecId) {
        this.edges.push([id, innerSpecId, 'NOT']);
      }
    } else {
      specType = 'Unknown';
      id = this.generateId(specType);
    }

    if (parentId) {
      this.edges.push([parentId, id, '']);
    }

    return id;
  }

  private traverseCompositeSpec(spec: any, id: number, leftProp: string, rightProp: string): void {
    if (spec[leftProp]) {
      this.traverseSpecification(spec[leftProp], id);
    }

    if (spec[rightProp]) {
      this.traverseSpecification(spec[rightProp], id);
    }
  }

  visualize(spec: Specification<T>, outputPath: string): void {
    const dotContent = this.buildGraph(spec);
    const dotFile = `${outputPath}.dot`;
    const pngFile = `${outputPath}.png`;

    fs.writeFileSync(dotFile, dotContent);
    execSync(`dot -Tpng ${dotFile} -o ${pngFile}`);

    console.log(`Decision tree visualized at ${pngFile}`);
  }
}

// Rules engine implementation - immutable by design
export class RulesEngine<T> {
  private readonly rules: ReadonlyArray<RuleResult<T>>;

  constructor(rules: ReadonlyArray<RuleResult<T>> = []) {
    this.rules = Object.freeze([...rules]);
    // Freeze the engine instance
    Object.freeze(this);
  }

  addRule(rule: RuleResult<T>): RulesEngine<T> {
    // Create new instance with the added rule to maintain immutability
    return new RulesEngine<T>([...this.rules, rule]);
  }

  evaluate(candidate: T): T {
    // Create immutable copy of the candidate
    let result = structuredClone(candidate);

    for (const rule of this.rules) {
      if (rule.specification.isSatisfiedBy(result)) {
        // Apply the action and create a new immutable result
        result = structuredClone(rule.action(result));
      }
    }

    return result;
  }

  visualizeRules(outputPath: string): void {
    if (this.rules.length === 0) return;

    // Combine all rules into a single specification for visualization
    let combinedSpec = this.rules[0].specification;

    for (let i = 1; i < this.rules.length; i++) {
      combinedSpec = combinedSpec.or(this.rules[i].specification);
    }

    const visualizer = new RuleVisualizer<T>();
    visualizer.visualize(combinedSpec, outputPath);
  }

  // Get a copy of the rules for inspection
  getRules(): ReadonlyArray<RuleResult<T>> {
    return this.rules;
  }

  // Get the decision tree as a Graphviz Digraph string
  getDecisionTreeDot(): string {
    if (this.rules.length === 0) return '';

    let combinedSpec = this.rules[0].specification;

    for (let i = 1; i < this.rules.length; i++) {
      combinedSpec = combinedSpec.or(this.rules[i].specification);
    }

    const visualizer = new RuleVisualizer<T>();
    return visualizer.buildGraph(combinedSpec);
  }
}

// DSL for creating business rules
export class RuleBuilder<T> {
  static create<T>(name: string, description: string): RuleBuilder<T> {
    return new RuleBuilder<T>(name, description);
  }

  private spec: Specification<T> | null = null;
  private readonly name: string;
  private readonly description: string;

  private constructor(name: string, description: string) {
    this.name = name;
    this.description = description;
    // Freeze builder for immutability during construction
    Object.freeze(this);
  }

  when(predicate: (t: T) => boolean): RuleBuilder<T> {
    const newBuilder = new RuleBuilder<T>(this.name, this.description);
    (newBuilder as any).spec = new BusinessRuleSpecification<T>(predicate, this.name, this.description);
    return newBuilder;
  }

  and(predicate: (t: T) => boolean): RuleBuilder<T> {
    if (!this.spec) throw new Error("Rule condition not set");

    const newBuilder = new RuleBuilder<T>(this.name, this.description);
    const newSpec = new BusinessRuleSpecification<T>(predicate, `${this.name}_and`, this.description);
    (newBuilder as any).spec = this.spec.and(newSpec);
    return newBuilder;
  }

  or(predicate: (t: T) => boolean): RuleBuilder<T> {
    if (!this.spec) throw new Error("Rule condition not set");

    const newBuilder = new RuleBuilder<T>(this.name, this.description);
    const newSpec = new BusinessRuleSpecification<T>(predicate, `${this.name}_or`, this.description);
    (newBuilder as any).spec = this.spec.or(newSpec);
    return newBuilder;
  }

  not(): RuleBuilder<T> {
    if (!this.spec) throw new Error("Rule condition not set");

    const newBuilder = new RuleBuilder<T>(this.name, this.description);
    (newBuilder as any).spec = this.spec.not();
    return newBuilder;
  }

  then(action: (t: T) => T): RuleResult<T> {
    if (!this.spec) throw new Error("Rule condition not set");

    // Create immutable rule result
    return Object.freeze({
      specification: Object.freeze(this.spec),
      action: action,
      name: this.name
    });
  }
}

