package com.example.kafka.processor;

import com.example.kafka.consumer.IKafkaConsumerWrapper;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.apache.kafka.clients.consumer.ConsumerRecords;
import java.time.Duration;
import java.util.Collections;
import java.util.concurrent.atomic.AtomicBoolean;

public class KafkaEventProcessor implements EventProcessor {
    private final IKafkaConsumerWrapper consumerWrapper;
    private final String topicName;
    private final AtomicBoolean running = new AtomicBoolean(false);
    private Thread processingThread;

    public KafkaEventProcessor(IKafkaConsumerWrapper consumerWrapper, String topicName) {
        this.consumerWrapper = consumerWrapper;
        this.topicName = topicName;
    }

    @Override
    public void processEvent(String event) {
        // Process individual event - can be overridden for custom processing logic
        System.out.println("Processing event: " + event);
    }

    @Override
    public void start() {
        if (running.compareAndSet(false, true)) {
            processingThread = new Thread(this::processEvents);
            processingThread.start();
        }
    }

    @Override
    public void stop() {
        if (running.compareAndSet(true, false)) {
            if (processingThread != null) {
                processingThread.interrupt();
                try {
                    processingThread.join(5000);
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                }
            }
            consumerWrapper.close();
        }
    }

    private void processEvents() {
        consumerWrapper.subscribe(Collections.singletonList(topicName));
        try {
            while (running.get() && !Thread.currentThread().isInterrupted()) {
                ConsumerRecords<String, String> records = consumerWrapper.poll(Duration.ofMillis(100));
                for (ConsumerRecord<String, String> record : records) {
                    processEvent(record.value());
                    System.out.println("Processed: offset = " + record.offset() + 
                                     ", key = " + record.key() + 
                                     ", value = " + record.value());
                }
                if (!records.isEmpty()) {
                    consumerWrapper.commitSync();
                }
            }
        } catch (Exception e) {
            if (running.get()) {
                System.err.println("Error processing events: " + e.getMessage());
            }
        } finally {
            consumerWrapper.close();
        }
    }
}

