    if (type === 'object' && !current.properties) {
      current.properties = {};
    }

    if (type === 'array' && !current.items) {
      current.items = { type: 'string' };
    }

    updateSchema(newSchema);
  };

  const addProperty = (path: string[]) => {
    const newSchema = JSON.parse(JSON.stringify(schema));
    let current = newSchema;

    for (let i = 0; i < path.length; i++) {
      if (path[i] === 'properties') continue;
      current = current[path[i]];
    }

    const newProperty = `property${Date.now()}`;
    if (!current.properties) current.properties = {};
    current.properties[newProperty] = { type: 'string' };

    updateSchema(newSchema);
  };

  const removeProperty = (path: string[]) => {
    const newSchema = JSON.parse(JSON.stringify(schema));
    let current = newSchema;

    for (let i = 0; i < path.length - 2; i++) {
      if (path[i] === 'properties') continue;
      current = current[path[i]];
    }

    const key = path[path.length - 1];
    if (current.properties && current.properties[key]) {
      delete current.properties[key];
    }

    updateSchema(newSchema);
  };

  const updateDescription = (path: string[], description: string) => {
    const newSchema = JSON.parse(JSON.stringify(schema));
    let current = newSchema;

    for (let i = 0; i < path.length - 1; i++) {
      if (path[i] === 'properties' || path[i] === 'items') continue;
      current = current[path[i]];
    }

    current.description = description;
    updateSchema(newSchema);
  };

  const showTooltip = (e: React.MouseEvent, description: string) => {
    setTooltipPosition({ x: e.clientX, y: e.clientY });
    setActiveTooltip(description);
  };

  const hideTooltip = () => {
    setActiveTooltip(null);
  };

  const renderSchemaEditor = (schema: JSONSchema, path: string[] = []) => {
    const currentPath = path.join('.');
    const error = validationErrors.find(e => e.path === currentPath);

    return (
      <div className="schema-field" style={{ marginLeft: path.length * 20 + 'px' }}>
        <div className="field-row">
          {path.length > 0 && path[path.length - 2] === 'properties' && (
            <input
              type="text"
              value={path[path.length - 1]}
              onChange={(e) => {
                const newPath = [...path];
                const oldKey = newPath.pop();
                const newKey = e.target.value;

                const newSchema = JSON.parse(JSON.stringify(schema));
                let current = newSchema;

                for (let i = 0; i < newPath.length - 1; i++) {
                  if (newPath[i] === 'properties') continue;
                  current = current[newPath[i]];
                }

                if (current.properties) {
                  const value = current.properties[oldKey!];
                  delete current.properties[oldKey!];
                  if (newKey) current.properties[newKey] = value;
                }

                updateSchema(newSchema);
              }}
              className="property-name"
            />
          )}

          <select
            value={schema.type}
            onChange={(e) => handleChangeType([...path, 'type'], e.target.value)}
            className="type-selector"
          >
            {fieldTypes.map(type => (
              <option key={type} value={type}>{type}</option>
            ))}
          </select>

          <input
            type="text"
            placeholder="Description"
            value={schema.description || ''}
            onChange={(e) => updateDescription([...path], e.target.value)}
            className="description-input"
          />

          {schema.description && (
            <button 
              className="tooltip-button"
              onMouseEnter={(e) => showTooltip(e, schema.description!)}
              onMouseLeave={hideTooltip}
            >
              ?
            </button>
          )}

          {path.length > 0 && (
            <button onClick={() => removeProperty(path)} className="remove-button">
              Delete
            </button>
          )}
        </div>

        {error && (
          <div className="error-message">{error.message}</div>
        )}

        {schema.type === 'object' && (
          <div className="object-properties">
            {schema.properties && Object.keys(schema.properties).map(key => (
              <div key={key} className="property-item">
                {renderSchemaEditor(schema.properties![key], [...path, 'properties', key])}
              </div>
            ))}
            <button onClick={() => addProperty([...path])} className="add-property-button">
              Add Property
            </button>
          </div>
        )}

        {schema.type === 'array' && schema.items && (
          <div className="array-items">
            <div className="items-label">Items:</div>
            {renderSchemaEditor(schema.items, [...path, 'items'])}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="schema-editor">
      <div className="toolbar">
        <button onClick={undo} disabled={history.length === 0} className="undo-button">
          Undo
        </button>
        <button onClick={redo} disabled={future.length === 0} className="redo-button">
          Redo
        </button>
      </div>

      <div className="editor-container">
        <div className="visual-editor">
          {renderSchemaEditor(schema)}
        </div>

        <div className="json-preview">
          <pre>{JSON.stringify(schema, null, 2)}</pre>
        </div>
      </div>

      {activeTooltip && tooltipPosition && (
        <div 
          className="tooltip" 
          style={{ 
            position: 'fixed', 
            top: tooltipPosition.y + 10 + 'px', 
            left: tooltipPosition.x + 10 + 'px' 
          }}
        >
          {activeTooltip}
        </div>
      )}
    </div>
  );
};

