// Configuration loaded from environment variables
type Config struct {
	ClientID            string
	ClientSecret        string
	RedirectURI         string
	AuthServerURL       string
	TokenServerURL      string
	Port                string
	TLSCert             string
	TLSKey              string
	DSN                 string
