package com.example.cleanarchitecture.application.mapper;

import com.example.cleanarchitecture.application.dto.UserDTO;
import com.example.cleanarchitecture.domain.model.User;
import org.springframework.stereotype.Component;

import java.util.List;
import java.util.stream.Collectors;

/**
 * Mapper class for converting between User domain entities and UserDTO objects.
 * Ensures separation between domain and application layers.
 */
@Component
public class UserMapper {

    /**
     * Converts a User domain entity to a UserDTO.
     *
     * @param user The User domain entity
     * @return A UserDTO representing the user
     */
    public UserDTO toDTO(User user) {
        if (user == null) {
            return null;
        }

        return UserDTO.builder()
                .id(user.getId())
                .name(user.getName())
                .email(user.getEmail())
                .role(user.getRole())
                .build();
    }

    /**
     * Converts a UserDTO to a User domain entity.
     *
     * @param userDTO The UserDTO object
     * @return A User domain entity
     */
    public User toEntity(UserDTO userDTO) {
        if (userDTO == null) {
            return null;
        }

        return User.builder()
                .id(userDTO.getId())
                .name(userDTO.getName())
                .email(userDTO.getEmail())
                .role(userDTO.getRole())
                .build();
    }

    /**
     * Converts a list of User domain entities to a list of UserDTOs.
     *
     * @param users The list of User domain entities
     * @return A list of UserDTOs
     */
    public List<UserDTO> toDTOList(List<User> users) {
        if (users == null) {
            return List.of();
        }

        return users.stream()
                .map(this::toDTO)
                .collect(Collectors.toList());
    }
}

// Application Layer - Service
package com.example.cleanarchitecture.application.service;

import com.example.cleanarchitecture.application.dto.UserDTO;
import com.example.cleanarchitecture.application.mapper.UserMapper;
import com.example.cleanarchitecture.domain.model.User;
import com.example.cleanarchitecture.domain.service.UserDomainService;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;
import java.util.Optional;

/**
 * Application service that orchestrates user operations.
 * Acts as a facade for the domain layer and handles use cases.
 */
@Service
@RequiredArgsConstructor
public class UserApplicationService {

    private final UserDomainService userDomainService;
    private final UserMapper userMapper;

    /**
     * Retrieves a user by their ID.
     *
     * @param id The ID of the user to retrieve
     * @return An Optional containing the user DTO if found
     */
    @Transactional(readOnly = true)
    public Optional<UserDTO> getUserById(Long id) {
        return userDomainService.getUserById(id)
                .map(userMapper::toDTO);
    }

    /**
     * Retrieves all users in the system.
     *
     * @return A list of all user DTOs
     */
    @Transactional(readOnly = true)
    public List<UserDTO> getAllUsers() {
        List<User> users = userDomainService.getAllUsers();
        return userMapper.toDTOList(users);
    }

    /**
     * Creates a new user.
     *
     * @param userDTO The user DTO containing the information for the new user
     * @return The created user DTO with an assigned ID
     * @throws IllegalArgumentException if the email is already in use or validation fails
     */
    @Transactional
    public UserDTO createUser(UserDTO userDTO) {
        User user = userMapper.toEntity(userDTO);
        User createdUser = userDomainService.createUser(user);
        return userMapper.toDTO(createdUser);
    }

    /**
     * Updates an existing user's information.
     *
     * @param id The ID of the user to update
     * @param userDTO The user DTO containing the updated information
     * @return An Optional containing the updated user DTO if found
     * @throws IllegalArgumentException if the email is already in use by another user
     */
    @Transactional
    public Optional<UserDTO> updateUser(Long id, UserDTO userDTO) {
        User user = userMapper.toEntity(userDTO);
        return userDomainService.updateUser(id, user)
                .map(userMapper::toDTO);
    }

    /**
     * Deletes a user by their ID.
     *
     * @param id The ID of the user to delete
     * @return true if the user was deleted, false if user was not found
     */
    @Transactional
    public boolean deleteUser(Long id) {
        return userDomainService.deleteUser(id);
    }
}

