#include <algorithm>
#include <chrono>
#include <fstream>
#include <iostream>
#include <mutex>
#include <queue>
#include <string>
#include <thread>
#include <vector>
#include <filesystem>
#include <atomic>
#include <iomanip>

const size_t MAX_MEMORY = 8ULL * 1024 * 1024 * 1024; // 8 GB
const size_t CHUNK_SIZE = 512ULL * 1024 * 1024; // 512 MB per chunk
const size_t BUFFER_SIZE = 64ULL * 1024 * 1024; // 64 MB I/O buffer

std::mutex mtx;
std::atomic<size_t> active_threads{0};

struct Record {
    int key;
    // Simulating larger records with padding
    char padding[28]; // Total 32 bytes per record

    bool operator<(const Record& other) const {
        return key < other.key;
    }
};

void sortChunk(const std::string& inputFile, size_t chunkIndex, const std::string& tempDir) {
    std::string chunkFileName = tempDir + "/chunk_" + std::to_string(chunkIndex) + ".tmp";

    std::ifstream in(inputFile, std::ios::binary);
    if (!in) {
        std::cerr << "Failed to open input file for chunk " << chunkIndex << std::endl;
        return;
    }

    // Position at the start of this chunk
    in.seekg(chunkIndex * CHUNK_SIZE);

    // Read chunk into memory
    std::vector<Record> records;
    records.reserve(CHUNK_SIZE / sizeof(Record));

    Record record;
    auto start = std::chrono::high_resolution_clock::now();

    while (records.size() < records.capacity() && in.read(reinterpret_cast<char*>(&record), sizeof(Record))) {
        records.push_back(record);
    }

    auto readEnd = std::chrono::high_resolution_clock::now();

    // Sort the chunk
    std::sort(records.begin(), records.end());

    auto sortEnd = std::chrono::high_resolution_clock::now();

    // Write sorted chunk to disk
    std::ofstream out(chunkFileName, std::ios::binary);
    if (!out) {
        std::cerr << "Failed to create temporary file for chunk " << chunkIndex << std::endl;
        return;
    }

    out.write(reinterpret_cast<const char*>(records.data()), records.size() * sizeof(Record));

    auto writeEnd = std::chrono::high_resolution_clock::now();

    std::lock_guard<std::mutex> lock(mtx);
    std::cout << "Chunk " << chunkIndex << " processed: " 
              << "Read " << std::chrono::duration<double>(readEnd-start).count() << "s, "
              << "Sort " << std::chrono::duration<double>(sortEnd-readEnd).count() << "s, "
              << "Write " << std::chrono::duration<double>(writeEnd-sortEnd).count() << "s" 
              << std::endl;

    active_threads--;
}

void mergeChunks(const std::vector<std::string>& chunkFiles, const std::string& outputFile) {
    struct ChunkReader {
        std::ifstream file;
        Record current;
        bool valid = false;

        bool operator>(const ChunkReader& other) const {
            return current.key > other.key;
        }
    };

    // Priority queue for merging
    auto comparator = [](const ChunkReader& a, const ChunkReader& b) { return a > b; };
    std::priority_queue<ChunkReader, std::vector<ChunkReader>, decltype(comparator)> pq(comparator);

    // Open all chunk files
    std::vector<ChunkReader> readers(chunkFiles.size());

    for (size_t i = 0; i < chunkFiles.size(); i++) {
        readers[i].file.open(chunkFiles[i], std::ios::binary);

        if (!readers[i].file) {
            std::cerr << "Failed to open chunk file: " << chunkFiles[i] << std::endl;
            continue;
        }

        // Read first record
        if (readers[i].file.read(reinterpret_cast<char*>(&readers[i].current), sizeof(Record))) {
            readers[i].valid = true;
            pq.push(readers[i]);
        }
    }

    // Open output file
    std::ofstream out(outputFile, std::ios::binary);
    if (!out) {
        std::cerr << "Failed to create output file: " << outputFile << std::endl;
        return;
    }

    // Set buffer for output
    std::vector<char> outBuffer(BUFFER_SIZE);
    out.rdbuf()->pubsetbuf(outBuffer.data(), outBuffer.size());

    // Merge
    std::vector<Record> outputBatch;
    outputBatch.reserve(BUFFER_SIZE / sizeof(Record));

    auto start = std::chrono::high_resolution_clock::now();
    size_t recordsProcessed = 0;

    while (!pq.empty()) {
        // Get top record (smallest key)
        ChunkReader current = pq.top();
        pq.pop();

        // Write to output batch
        outputBatch.push_back(current.current);
        recordsProcessed++;

        // Flush batch if full
        if (outputBatch.size() >= outputBatch.capacity()) {
            out.write(reinterpret_cast<const char*>(outputBatch.data()), 
                     outputBatch.size() * sizeof(Record));
            outputBatch.clear();
        }

        // Read next record from this chunk
        if (current.file.read(reinterpret_cast<char*>(&current.current), sizeof(Record))) {
            pq.push(current);
        }
    }

    // Write any remaining records
    if (!outputBatch.empty()) {
        out.write(reinterpret_cast<const char*>(outputBatch.data()), 
                 outputBatch.size() * sizeof(Record));
    }

    auto end = std::chrono::high_resolution_clock::now();
    std::cout << "Merged " << recordsProcessed << " records in " 
              << std::chrono::duration<double>(end-start).count() << " seconds" << std::endl;

    // Close files
    out.close();
    for (auto& reader : readers) {
        if (reader.file.is_open()) {
            reader.file.close();
        }
    }
}

int main(int argc, char* argv[]) {
    if (argc != 3) {
        std::cerr << "Usage: " << argv[0] << " <input file> <output file>" << std::endl;
        return 1;
    }

    std::string inputFile = argv[1];
    std::string outputFile = argv[2];
    std::string tempDir = "./temp";

    // Create temp directory
    std::filesystem::create_directories(tempDir);

    auto totalStart = std::chrono::high_resolution_clock::now();

    // Get file size
    std::ifstream inFile(inputFile, std::ios::binary | std::ios::ate);
    if (!inFile) {
        std::cerr << "Failed to open input file: " << inputFile << std::endl;
        return 1;
    }

    size_t fileSize = inFile.tellg();
    inFile.close();

    // Calculate number of chunks
    size_t numChunks = (fileSize + CHUNK_SIZE - 1) / CHUNK_SIZE;
    std::cout << "Processing " << fileSize / (1024.0 * 1024.0 * 1024.0) << " GB in " 
              << numChunks << " chunks" << std::endl;

    // Determine optimal thread count
    unsigned int numThreads = std::min(std::thread::hardware_concurrency(), 
                                      static_cast<unsigned int>(numChunks));
    std::cout << "Using " << numThreads << " threads" << std::endl;

    // Sort chunks in parallel
    std::vector<std::thread> threads;
    std::vector<std::string> chunkFiles;

    auto sortStart = std::chrono::high_resolution_clock::now();

    for (size_t i = 0; i < numChunks; i++) {
        // Wait if too many active threads
        while (active_threads >= numThreads) {
            std::this_thread::sleep_for(std::chrono::milliseconds(10));
        }

        active_threads++;
        threads.emplace_back(sortChunk, inputFile, i, tempDir);
        chunkFiles.push_back(tempDir + "/chunk_" + std::to_string(i) + ".tmp");
    }

    // Wait for all threads to finish
    for (auto& thread : threads) {
        if (thread.joinable()) {
            thread.join();
        }
    }

    auto sortEnd = std::chrono::high_resolution_clock::now();
    std::cout << "All chunks sorted in " 
              << std::chrono::duration<double>(sortEnd-sortStart).count() << " seconds" << std::endl;

    // Merge sorted chunks
    auto mergeStart = std::chrono::high_resolution_clock::now();
    mergeChunks(chunkFiles, outputFile);
    auto mergeEnd = std::chrono::high_resolution_clock::now();

    std::cout << "Chunks merged in " 
              << std::chrono::duration<double>(mergeEnd-mergeStart).count() << " seconds" << std::endl;

    // Clean up temp files
    for (const auto& file : chunkFiles) {
        std::filesystem::remove(file);
    }
    std::filesystem::remove(tempDir);

    auto totalEnd = std::chrono::high_resolution_clock::now();

    // Print benchmark results
    double totalTime = std::chrono::duration<double>(totalEnd-totalStart).count();
    double sortTime = std::chrono::duration<double>(sortEnd-sortStart).count();
    double mergeTime = std::chrono::duration<double>(mergeEnd-mergeStart).count();
    double throughput = fileSize / (1024.0 * 1024.0 * 1024.0) / totalTime;

    std::cout << "\n=========== BENCHMARK RESULTS ===========" << std::endl;
    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Input size:      " << fileSize / (1024.0 * 1024.0 * 1024.0) << " GB" << std::endl;
    std::cout << "Sort time:       " << sortTime << " s" << std::endl;
    std::cout << "Merge time:      " << mergeTime << " s" << std::endl;
    std::cout << "Total time:      " << totalTime << " s" << std::endl;
    std::cout << "Throughput:      " << throughput << " GB/s" << std::endl;
    std::cout << "I/O percentage:  " << (mergeTime / totalTime) * 100 << "%" << std::endl;
    std::cout << "CPU utilization: " << (sortTime / totalTime) * 100 << "%" << std::endl;
    std::cout << "Threads used:    " << numThreads << std::endl;
    std::cout << "=========================================" << std::endl;

    return 0;
}

# graph_search_framework.py

from abc import ABC, abstractmethod
import importlib
import pkgutil
from typing import Dict, Tuple, List, Any, Type
import heapq

class GraphSearch(ABC):
    @abstractmethod
    def search(self, start: Any, goal: Any) -> List[Any]:
        """Perform the search and return the path from start to goal as a list."""
        pass

class Graph(ABC):
    @abstractmethod
    def get_neighbors(self, node: Any) -> List[Any]:
        """Return the list of neighbors for a given node."""
        pass

    @abstractmethod
    def cost(self, current: Any, neighbor: Any) -> float:
        """Return the cost of moving from the current node to a neighbor."""
        pass

    @abstractmethod
    def heuristic(self, current: Any, goal: Any) -> float:
        """Return the heuristic estimate of the cost from current node to the goal."""
        pass


# plugin_discovery.py

def discover_plugins() -> Dict[str, Type[GraphSearch]]:
    plugins = {}
    for module_info in pkgutil.iter_modules():
        try:
            module = importlib.import_module(module_info.name)
            for attribute_name in dir(module):
                attribute = getattr(module, attribute_name)
                if isinstance(attribute, type) and issubclass(attribute, GraphSearch) and attribute is not GraphSearch:
                    plugins[attribute.__name__] = attribute
        except (ImportError, AttributeError):
            continue
    return plugins


# dijkstra_plugin.py

class DijkstraSearch(GraphSearch):
    def __init__(self, graph: Graph):
        self.graph = graph

    def search(self, start: Any, goal: Any) -> List[Any]:
        distances = {start: 0}
        previous = {}
        visited = set()
        heap = [(0, start)]

        while heap:
            current_distance, current = heapq.heappop(heap)

            if current in visited:
                continue

            visited.add(current)

            if current == goal:
                path = []
                while current is not None:
                    path.append(current)
                    current = previous.get(current)
                return path[::-1]

            for neighbor in self.graph.get_neighbors(current):
                if neighbor not in visited:
                    distance = current_distance + self.graph.cost(current, neighbor)

                    if neighbor not in distances or distance < distances[neighbor]:
                        distances[neighbor] = distance
                        previous[neighbor] = current
                        heapq.heappush(heap, (distance, neighbor))

        return []


# astar_plugin.py

class AStarSearch(GraphSearch):
    def __init__(self, graph: Graph):
        self.graph = graph

    def search(self, start: Any, goal: Any) -> List[Any]:
        open_set = [(0, start)]
        came_from = {}
        g_score = {start: 0}
        f_score = {start: self.graph.heuristic(start, goal)}

        while open_set:
            current_f, current = heapq.heappop(open_set)

            if current == goal:
                path = []
                while current in came_from:
                    path.append(current)
                    current = came_from[current]
                path.append(start)
                return path[::-1]

            for neighbor in self.graph.get_neighbors(current):
                tentative_g_score = g_score[current] + self.graph.cost(current, neighbor)

                if neighbor not in g_score or tentative_g_score < g_score[neighbor]:
                    came_from[neighbor] = current
                    g_score[neighbor] = tentative_g_score
                    f_score[neighbor] = tentative_g_score + self.graph.heuristic(neighbor, goal)
                    heapq.heappush(open_set, (f_score[neighbor], neighbor))

        return []


