class BellmanFordSearch(GraphSearch):
    def __init__(self, graph: Graph):
        self.graph = graph
        self.all_nodes = []

    def search(self, start: Any, goal: Any) -> List[Any]:
        # Get all nodes - this is a simplified approach
        # In practice, you'd need a way to enumerate all nodes
        distances = {start: 0}
        previous = {}

        # Relax edges repeatedly
        for _ in range(len(self.all_nodes) - 1):
            for node in self.all_nodes:
                if node in distances:
                    for neighbor in self.graph.get_neighbors(node):
                        new_distance = distances[node] + self.graph.cost(node, neighbor)
                        if neighbor not in distances or new_distance < distances[neighbor]:
                            distances[neighbor] = new_distance
                            previous[neighbor] = node

        # Check for negative cycles
        for node in self.all_nodes:
            if node in distances:
                for neighbor in self.graph.get_neighbors(node):
                    if distances[node] + self.graph.cost(node, neighbor) < distances.get(neighbor, float('inf')):
                        raise ValueError("Graph contains negative cycle")

        # Reconstruct path
        if goal not in distances:
            return []

        path = []
        current = goal
        while current is not None:
            path.append(current)
            current = previous.get(current)

        return path[::-1]


