// listenForRequestVote handles incoming RequestVote RPCs
func (s *RaftServer) listenForRequestVote(peer int) {
	for args := range s.requestVoteCh[peer] {
		s.mu.Lock()

		reply := RequestVoteReply{
			Term:        s.currentTerm,
			VoteGranted: false,
		}

		if args.Term < s.currentTerm {
			// Reply false if term < currentTerm
			s.mu.Unlock()
			if !s.isPartitioned(peer) {
				s.requestVoteRespCh[peer] <- reply
			}
			continue
		}

		if args.Term > s.currentTerm {
			// If RPC request contains term T > currentTerm: set currentTerm = T, convert to follower
			s.currentTerm = args.Term
			s.state = Follower
			s.votedFor = -1
			s.leader = -1
			reply.Term = s.currentTerm
		}

		lastLogIndex := len(s.log) - 1
		lastLogTerm := 0
		if lastLogIndex >= 0 {
			lastLogTerm = s.log[lastLogIndex].Term
		}

		// If votedFor is null or candidateId, and candidate's log is at least as up-to-date as receiver's log, grant vote
		if (s.votedFor == -1 || s.votedFor == args.CandidateID) &&
			(args.LastLogTerm > lastLogTerm || 
				(args.LastLogTerm == lastLogTerm && args.LastLogIndex >= lastLogIndex)) {
			s.votedFor = args.CandidateID
			reply.VoteGranted = true
			s.logger.Printf("Server %d: granted vote to %d for term %d\n", s.id, args.CandidateID, args.Term)
		}

		s.mu.Unlock()

		if !s.isPartitioned(peer) {
			s.requestVoteRespCh[peer] <- reply
		}
	}
}

