func (s *RaftServer) listenForAppendEntries(peer int) {
	for args := range s.appendEntriesCh[peer] {
		s.mu.Lock()

		reply := AppendEntriesReply{
			Term:    s.currentTerm,
			Success: false,
		}

		if args.Term < s.currentTerm {
