	if n.state != Leader {
		n.mu.Unlock()
		return
	}

	n.logger.Printf("Node %d: sending heartbeats for term %d", n.id, n.currentTerm)

	for _, peerID := range n.nodes {
		if peerID == n.id || n.isPartitioned(peerID) {
			continue
		}

		prevLogIndex := n.nextIndex[peerID] - 1
		prevLogTerm := 0
		if prevLogIndex >= 0 && prevLogIndex < len(n.log) {
			prevLogTerm = n.log[prevLogIndex].Term
		}

		entries := []LogEntry{}
		if n.nextIndex[peerID] < len(n.log) {
			entries = n.log[n.nextIndex[peerID]:]
		}

		args := &AppendEntriesArgs{
			Term:         n.currentTerm,
			LeaderID:     n.id,
			PrevLogIndex: prevLogIndex,
			PrevLogTerm:  prevLogTerm,
			Entries:      entries,
			LeaderCommit: n.commitIndex,
		}

		go func(peer int, args *AppendEntriesArgs) {
			n.network.Send(n.id, peer, args)
		}(peerID, args)
	}
	n.mu.Unlock()
}

// HandleRequestVote handles a RequestVote RPC
