	lastLogIndex := len(n.log) - 1
	lastLogTerm := n.log[lastLogIndex].Term

	if (n.votedFor == -1 || n.votedFor == args.CandidateID) &&
		(args.LastLogTerm > lastLogTerm || 
		 (args.LastLogTerm == lastLogTerm && args.LastLogIndex >= lastLogIndex)) {
		n.votedFor = args.CandidateID
		reply.VoteGranted = true
		n.resetElectionTimer()
		n.logger.Printf("Node %d: granted vote to %d for term %d", n.id, args.CandidateID, args.Term)
	} else {
		n.logger.Printf("Node %d: rejected vote for %d (term %d)", n.id, args.CandidateID, args.Term)
	}

	n.network.Send(n.id, args.CandidateID, reply)
