// HandleAppendEntries handles an AppendEntries RPC
func (n *Node) handleAppendEntries(args *AppendEntriesArgs) {
	n.mu.Lock()
	defer n.mu.Unlock()

	reply := &AppendEntriesReply{
		Term:    n.currentTerm,
		Success: false,
	}

	if args.Term < n.currentTerm {
		n.network.Send(n.id, args.LeaderID, reply)
		return
	}

	n.resetElectionTimer()

	if args.Term > n.currentTerm {
		n.currentTerm = args.Term
		n.votedFor = -1
	}

	n.state = Follower

	// Check if log contains an entry at prevLogIndex with term prevLogTerm
	if args.PrevLogIndex >= len(n.log) || 
		(args.PrevLogIndex > 0 && n.log[args.PrevLogIndex].Term != args.PrevLogTerm) {
		n.network.Send(n.id, args.LeaderID, reply)
		return
	}

	// If existing entries conflict with new ones, delete them and all that follow
	conflictIndex := -1
	for i := 0; i < len(args.Entries); i++ {
		if args.PrevLogIndex+1+i >= len(n.log) {
			break
		}
		if n.log[args.PrevLogIndex+1+i].Term != args.Entries[i].Term {
			conflictIndex = args.PrevLogIndex + 1 + i
			break
		}
	}

	if conflictIndex != -1 {
		n.log = n.log[:conflictIndex]
	}

	// Append new entries not already in the log
	if len(args.Entries) > 0 {
		startIdx := args.PrevLogIndex + 1
		if startIdx < len(n.log) {
			n.log = append(n.log[:startIdx], args.Entries...)
		} else {
			n.log = append(n.log, args.Entries...)
		}
	}

	// Update commitIndex
	if args.LeaderCommit > n.commitIndex {
		n.commitIndex = min(args.LeaderCommit, len(n.log)-1)
		n.applyCommittedEntries()
	}

	reply.Success = true
	n.network.Send(n.id, args.LeaderID, reply)
}

// HandleAppendEntriesReply processes an AppendEntries RPC response
func (n *Node) handleAppendEntriesReply(reply *AppendEntriesReply, peerID int) {
	n.mu.Lock()
	defer n.mu.Unlock()

	if n.state != Leader {
		return
	}

	if reply.Term > n.currentTerm {
		n.currentTerm = reply.Term
		n.state = Follower
		n.votedFor = -1
		n.resetElectionTimer()
		return
	}

	if reply.Success {
		// Update nextIndex and matchIndex for this follower
		n.nextIndex[peerID] = len(n.log)
		n.matchIndex[peerID] = n.nextIndex[peerID] - 1

		// Check if we can commit any entries
		n.updateCommitIndex()
	} else {
		// Decrement nextIndex and retry
		n.nextIndex[peerID] = max(1, n.nextIndex[peerID]-1)
	}
}

// UpdateCommitIndex checks if we can advance the commit index
func (n *Node) updateCommitIndex() {
	// For each entry in the log...
	for i := n.commitIndex + 1; i < len(n.log); i++ {
		// Only commit entries from current term
		if n.log[i].Term != n.currentTerm {
			continue
		}

		// Count nodes that have this entry
		count := 1 // Leader has the entry
		for _, peerID := range n.nodes {
			if peerID != n.id && n.matchIndex[peerID] >= i {
				count++
			}
		}

		// If a majority have the entry, commit it
		if count >= n.majority {
			n.commitIndex = i
			n.applyCommittedEntries()
		}
	}
}

// ApplyCommittedEntries applies all committed log entries
func (n *Node) applyCommittedEntries() {
	for i := n.lastApplied + 1; i <= n.commitIndex; i++ {
		n.logger.Printf("Node %d: applying command: %s", n.id, n.log[i].Command)
		// In a real implementation, we would apply the command to the state machine
		n.lastApplied = i
	}
}

// SubmitCommand submits a command to the leader
func (n *Node) SubmitCommand(command string) bool {
	n.mu.Lock()
	defer n.mu.Unlock()

	if n.state != Leader {
		return false
	}

	n.log = append(n.log, LogEntry{Term: n.currentTerm, Command: command})
	n.logger.Printf("Node %d: received new command: %s", n.id, command)
	return true
}

// IsPartitioned checks if this node is partitioned from another node
func (n *Node) isPartitioned(peerID int) bool {
	return n.partitions[peerID]
}

// CreatePartition creates a network partition between this node and another
func (n *Node) CreatePartition(peerID int) {
	n.mu.Lock()
	defer n.mu.Unlock()
	n.partitions[peerID] = true
	n.logger.Printf("Node %d: created partition with %d", n.id, peerID)
}

// HealPartition heals a network partition between this node and another
func (n *Node) HealPartition(peerID int) {
	n.mu.Lock()
	defer n.mu.Unlock()
	delete(n.partitions, peerID)
	n.logger.Printf("Node %d: healed partition with %d", n.id, peerID)
}

// Crash simulates a node crash
func (n *Node) Crash() {
	n.mu.Lock()
	defer n.mu.Unlock()
	n.active = false
	n.logger.Printf("Node %d: crashed", n.id)
}

// Restart simulates a node restart
func (n *Node) Restart() {
	n.mu.Lock()
	n.active = true
	n.state = Follower
	n.votedFor = -1
	n.logger.Printf("Node %d: restarted", n.id)
	n.mu.Unlock()
	n.resetElectionTimer()
}

// GetState returns the current state of the node
func (n *Node) GetState() (RaftState, int, int) {
	n.mu.Lock()
	defer n.mu.Unlock()
	return n.state, n.currentTerm, n.commitIndex
}

