	logger.Println("TEST 1: Submitting commands to stable cluster")
	for i := 0; i < 5; i++ {
		cmd := fmt.Sprintf("command-%d", i)
		if nodes[leaderID].SubmitCommand(cmd) {
			logger.Printf("Submitted command: %s to leader %d", cmd, leaderID)
		}
		time.Sleep(100 * time.Millisecond)
	}

	// Test 2: Crash the leader
	logger.Println("TEST 2: Crashing the leader")
	nodes[leaderID].Crash()
	time.Sleep(1 * time.Second)

	// Find the new leader
	newLeaderID := findLeader(nodes)
	if newLeaderID != -1 {
		logger.Printf("New leader after crash: Node %d", newLeaderID)

		// Test 3: Submit commands to new leader
		logger.Println("TEST 3: Submitting commands to new leader")
		for i := 5; i < 10; i++ {
