			if nodes[newLeaderID].SubmitCommand(cmd) {
				logger.Printf("Submitted command: %s to new leader %d", cmd, newLeaderID)
			}
			time.Sleep(100 * time.Millisecond)
		}
	} else {
		logger.Println("No new leader elected after crash")
	}

	// Test 4: Restart the crashed leader
	logger.Println("TEST 4: Restarting the crashed leader")
	nodes[leaderID].Restart()
	time.Sleep(500 * time.Millisecond)

	// Test 5: Network partition
	if newLeaderID != -1 {
		logger.Println("TEST 5: Creating network partition")
		createPartition(nodes, newLeaderID)
		time.Sleep(1 * time.Second)

		// Find leader in majority partition
		majorityLeaderID := findLeader(nodes)
		if majorityLeaderID != -1 && majorityLeaderID != newLeaderID {
			logger.Printf("Leader in majority partition: Node %d", majorityLeaderID)

			// Test 6: Submit commands to majority partition
			logger.Println("TEST 6: Submitting commands to majority partition")
			for i := 10; i < 15; i++ {
