				}
				time.Sleep(100 * time.Millisecond)
			}
		}

		// Test 7: Heal partition
		logger.Println("TEST 7: Healing network partition")
		healPartition(nodes)
		time.Sleep(1 * time.Second)
	}

	// Test 8: Multiple node failures
	logger.Println("TEST 8: Causing multiple node failures")
	failCount := len(nodes) / 2
	for i := 0; i < failCount; i++ {
		nodes[i].Crash()
		logger.Printf("Crashed node %d", i)
	}
	time.Sleep(1 * time.Second)

	// Test 9: Verify cluster still functions with majority
	currentLeaderID := findLeader(nodes)
	if currentLeaderID != -1 {
		logger.Printf("Leader after multiple failures: Node %d", currentLeaderID)
		logger.Println("TEST 9: Submitting commands after multiple failures")
		for i := 15; i < 20; i++ {
			cmd := fmt.Sprintf("command-%d", i)
			if nodes[currentLeaderID].SubmitCommand(cmd) {
				logger.Printf("Submitted command: %s to leader %d", cmd, currentLeaderID)
			}
			time.Sleep(100 * time.Millisecond)
		}
	} else {
		logger.Println("No leader elected after multiple failures (expected if majority down)")
	}

	// Test 10: Restart failed nodes
	logger.Println("TEST 10: Restarting failed nodes")
	for i := 0; i < failCount; i++ {
		nodes[i].Restart()
		logger.Printf("Restarted node %d", i)
	}
	time.Sleep(1 * time.Second)

	// Verify log consistency
	verifyLogConsistency(nodes, logger)

	logger.Println("Fault injection tests completed")
}

// FindLeader returns the ID of the current leader or -1 if no leader
func findLeader(nodes []*Node) int {
	for i, node := range nodes {
		state, _, _ := node.GetState()
		if state == Leader {
			return i
		}
	}
	return -1
}

// CreatePartition creates a network partition separating a minority of nodes
func createPartition(nodes []*Node, nodeID int) {
	minorityCount := len(nodes) / 2
	for i := 0; i < len(nodes); i++ {
		if i < minorityCount {
			// Minority partition
			for j := minorityCount; j < len(nodes); j++ {
				nodes[i].CreatePartition(j)
				nodes[j].CreatePartition(i)
			}
		}
	}
}

// HealPartition heals all network partitions
func healPartition(nodes []*Node) {
	for i := 0; i < len(nodes); i++ {
		for j := 0; j < len(nodes); j++ {
			if i != j {
				nodes[i].HealPartition(j)
			}
		}
	}
}

// VerifyLogConsistency checks if logs are consistent across all nodes
func verifyLogConsistency(nodes []*Node, logger *log.Logger) {
	logger.Println("Verifying log consistency across nodes")

	// Find the node with the highest commit index
	maxCommitIndex := -1
	referenceNodeID := -1

	for i, node := range nodes {
		_, _, commitIndex := node.GetState()
		if commitIndex > maxCommitIndex {
			maxCommitIndex = commitIndex
			referenceNodeID = i
		}
	}

	if referenceNodeID == -1 {
		logger.Println("No node with committed entries found")
		return
	}

	logger.Printf("Reference node is %d with commit index %d", referenceNodeID, maxCommitIndex)

	// Check consistency
	inconsistencies := 0
	for i, node := range nodes {
		if i == referenceNodeID {
			continue
		}

		_, _, nodeCommitIndex := node.GetState()
		minCommitIndex := min(maxCommitIndex, nodeCommitIndex)

		// In a real implementation, we would compare the actual logs
		// This is a simplified check
		if minCommitIndex >= 0 {
			logger.Printf("Node %d has committed entries up to index %d", i, minCommitIndex)
		} else {
			logger.Printf("Node %d has no committed entries", i)
			inconsistencies++
		}
	}

	if inconsistencies == 0 {
		logger.Println("All nodes have consistent logs")
	} else {
		logger.Printf("Found %d nodes with potential log inconsistencies", inconsistencies)
	}
}
