// ConvexHull.cpp
#include "Geometry.h"
#include <algorithm>
#include <stack>

namespace geometry {
    // Utility function to determine if we make a counter-clockwise turn
    bool ccw(const Point& a, const Point& b, const Point& c) {
        return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x) > 0;
    }

    std::vector<Point> ConvexHull::compute(const std::vector<Point>& points) {
        if (points.size() <= 2) return points;

        // Create a copy of points for sorting
        std::vector<Point> sortedPoints = points;

        // Find the point with the lowest y-coordinate (and leftmost if tied)
        auto p0 = std::min_element(sortedPoints.begin(), sortedPoints.end(), 
            [](const Point& a, const Point& b) {
                return a.y < b.y || (a.y == b.y && a.x < b.x);
            });

        // Swap the lowest point to the first position
        std::swap(*p0, sortedPoints[0]);
        Point pivot = sortedPoints[0];

        // Sort points by polar angle with respect to pivot
        std::sort(sortedPoints.begin() + 1, sortedPoints.end(), 
            [&pivot](const Point& a, const Point& b) {
                double cross = (a - pivot).cross(b - pivot);
                if (std::abs(cross) < 1e-9) {
                    // If collinear, sort by distance from pivot
                    return a.dist2(pivot) < b.dist2(pivot);
                }
                return cross > 0;
            });

        // Graham's scan algorithm
        std::vector<Point> hull;
        for (const auto& point : sortedPoints) {
            // Pop back while we have a non-left turn
            while (hull.size() > 1 && !ccw(hull[hull.size() - 2], hull.back(), point)) {
                hull.pop_back();
            }
            hull.push_back(point);
        }

        return hull;
    }
}

