#include "Geometry.h"
#include <algorithm>
#include <cmath>
#include <limits>
#include <set>

namespace geometry {
    // Utility for Delaunay triangulation
    struct Triangle {
        Point a, b, c;
        Point circumcenter;
        double radius_squared;

        Triangle(const Point& a, const Point& b, const Point& c) : a(a), b(b), c(c) {
            // Calculate circumcenter and radius
            double D = 2 * (a.x * (b.y - c.y) + b.x * (c.y - a.y) + c.x * (a.y - b.y));
            double x = ((a.x * a.x + a.y * a.y) * (b.y - c.y) + 
                         (b.x * b.x + b.y * b.y) * (c.y - a.y) + 
                         (c.x * c.x + c.y * c.y) * (a.y - b.y)) / D;
            double y = ((a.x * a.x + a.y * a.y) * (c.x - b.x) + 
                         (b.x * b.x + b.y * b.y) * (a.x - c.x) + 
                         (c.x * c.x + c.y * c.y) * (b.x - a.x)) / D;

            circumcenter = Point(x, y);
            radius_squared = circumcenter.dist2(a);
        }

        bool containsInCircumcircle(const Point& p) const {
            return circumcenter.dist2(p) <= radius_squared + 1e-9;
        }

        std::tuple<Point, Point, Point> toTuple() const {
            return std::make_tuple(a, b, c);
        }
    };

    std::vector<std::tuple<Point, Point, Point>> DelaunayTriangulation::compute(const std::vector<Point>& points) {
        if (points.size() < 3) return {};

        // Create a super-triangle that contains all points
        double minX = std::numeric_limits<double>::max();
        double minY = std::numeric_limits<double>::max();
        double maxX = std::numeric_limits<double>::lowest();
        double maxY = std::numeric_limits<double>::lowest();

        for (const auto& p : points) {
            minX = std::min(minX, p.x);
            minY = std::min(minY, p.y);
            maxX = std::max(maxX, p.x);
            maxY = std::max(maxY, p.y);
        }

        double dx = maxX - minX;
        double dy = maxY - minY;
        double dmax = std::max(dx, dy);
        double xmid = (minX + maxX) / 2;
        double ymid = (minY + maxY) / 2;

        Point p1(xmid - 20 * dmax, ymid - dmax);
        Point p2(xmid, ymid + 20 * dmax);
        Point p3(xmid + 20 * dmax, ymid - dmax);

        std::vector<Triangle> triangles = {Triangle(p1, p2, p3)};

        // Add points one by one
        for (const auto& p : points) {
            std::vector<Triangle> badTriangles;

            // Find all triangles that contain p in their circumcircle
            for (const auto& t : triangles) {
                if (t.containsInCircumcircle(p)) {
                    badTriangles.push_back(t);
                }
            }

            // Find boundary of the polygonal hole
            std::set<std::pair<Point, Point>> edges;
            for (const auto& t : badTriangles) {
                std::pair<Point, Point> e1(t.a, t.b);
                std::pair<Point, Point> e2(t.b, t.c);
                std::pair<Point, Point> e3(t.c, t.a);

                if (e1.first.x > e1.second.x || (e1.first.x == e1.second.x && e1.first.y > e1.second.y))
                    std::swap(e1.first, e1.second);
                if (e2.first.x > e2.second.x || (e2.first.x == e2.second.x && e2.first.y > e2.second.y))
                    std::swap(e2.first, e2.second);
                if (e3.first.x > e3.second.x || (e3.first.x == e3.second.x && e3.first.y > e3.second.y))
                    std::swap(e3.first, e3.second);

                if (edges.find(e1) != edges.end())
                    edges.erase(e1);
                else
                    edges.insert(e1);

                if (edges.find(e2) != edges.end())
                    edges.erase(e2);
                else
                    edges.insert(e2);

                if (edges.find(e3) != edges.end())
                    edges.erase(e3);
                else
                    edges.insert(e3);
            }

            // Remove bad triangles
            triangles.erase(
                std::remove_if(triangles.begin(), triangles.end(), 
                    [&badTriangles](const Triangle& t) {
                        return std::find(badTriangles.begin(), badTriangles.end(), t) != badTriangles.end();
                    }),
                triangles.end());

            // Create new triangles from the edges and the point
            for (const auto& edge : edges) {
                triangles.push_back(Triangle(edge.first, edge.second, p));
            }
        }

        // Remove triangles that contain vertices of the super-triangle
        triangles.erase(
            std::remove_if(triangles.begin(), triangles.end(),
                [&p1, &p2, &p3](const Triangle& t) {
                    return t.a == p1 || t.a == p2 || t.a == p3 ||
                           t.b == p1 || t.b == p2 || t.b == p3 ||
                           t.c == p1 || t.c == p2 || t.c == p3;
                }),
            triangles.end());

        // Convert to tuples
        std::vector<std::tuple<Point, Point, Point>> result;
        for (const auto& t : triangles) {
            result.push_back(t.toTuple());
        }

        return result;
    }
}

