        // Compute Delaunay triangulation
        auto delaunay = DelaunayTriangulation::compute(points);

        // Map to store Voronoi cells for each input point
        std::map<Point, std::set<Point>> voronoiCells;

        // Calculate circumcenters of Delaunay triangles
        for (const auto& triangle : delaunay) {
            Point a, b, c;
            std::tie(a, b, c) = triangle;

            // Calculate circumcenter
            double D = 2 * (a.x * (b.y - c.y) + b.x * (c.y - a.y) + c.x * (a.y - b.y));
            double x = ((a.x * a.x + a.y * a.y) * (b.y - c.y) + 
                         (b.x * b.x + b.y * b.y) * (c.y - a.y) + 
                         (c.x * c.x + c.y * c.y) * (a.y - b.y)) / D;
            double y = ((a.x * a.x + a.y * a.y) * (c.x - b.x) + 
                         (b.x * b.x + b.y * b.y) * (a.x - c.x) + 
                         (c.x * c.x + c.y * c.y) * (b.x - a.x)) / D;

            Point circumcenter(x, y);

            // Add circumcenter to the Voronoi cells of the triangle vertices
            voronoiCells[a].insert(circumcenter);
            voronoiCells[b].insert(circumcenter);
            voronoiCells[c].insert(circumcenter);
        }

        // Convert to the required format
        std::vector<std::vector<Point>> result;
        for (const auto& entry : voronoiCells) {
            std::vector<Point> cell(entry.second.begin(), entry.second.end());

            // Order points to form a polygon (optional)
            if (cell.size() > 2) {
                // Find centroid
                Point centroid(0, 0);
                for (const auto& p : cell) {
                    centroid = centroid + p;
                }
                centroid.x /= cell.size();
                centroid.y /= cell.size();

                // Sort points by angle around centroid
                std::sort(cell.begin(), cell.end(), [&centroid](const Point& a, const Point& b) {
                    return std::atan2(a.y - centroid.y, a.x - centroid.x) < 
                           std::atan2(b.y - centroid.y, b.x - centroid.x);
                });
            }

            result.push_back(cell);
        }

        return result;
    }
}

// GeometryTests.cpp
#include "Geometry.h"
#include <cassert>
#include <iostream>
#include <random>
#include <chrono>
#include <algorithm>
#include <cmath>

// Utility functions for testing
namespace testing {
    // Generate random points
    std::vector<geometry::Point> generateRandomPoints(int count, double minVal = 0.0, double maxVal = 100.0) {
        std::vector<geometry::Point> points;
        unsigned seed = std::chrono::system_clock::now().time_since_epoch().count();
        std::default_random_engine generator(seed);
        std::uniform_real_distribution<double> distribution(minVal, maxVal);

        for (int i = 0; i < count; ++i) {
            points.emplace_back(distribution(generator), distribution(generator));
        }

        return points;
    }

    // Check if a point is inside a polygon
    bool isPointInPolygon(const geometry::Point& point, const std::vector<geometry::Point>& polygon) {
        if (polygon.size() < 3) return false;

        bool inside = false;
        for (size_t i = 0, j = polygon.size() - 1; i < polygon.size(); j = i++) {
            if (((polygon[i].y > point.y) != (polygon[j].y > point.y)) &&
                (point.x < (polygon[j].x - polygon[i].x) * (point.y - polygon[i].y) / 
                           (polygon[j].y - polygon[i].y) + polygon[i].x)) {
                inside = !inside;
            }
        }

        return inside;
    }

    // Calculate area of a polygon
    double polygonArea(const std::vector<geometry::Point>& polygon) {
        double area = 0.0;
        int j = polygon.size() - 1;

        for (size_t i = 0; i < polygon.size(); i++) {
            area += (polygon[j].x + polygon[i].x) * (polygon[j].y - polygon[i].y);
            j = i;
        }

        return std::abs(area / 2.0);
    }
}

// Test ConvexHull
void testConvexHull() {
    std::cout << "Testing ConvexHull..." << std::endl;

    // Test with simple square
    std::vector<geometry::Point> points {{0,0}, {1,0}, {0,1}, {1,1}, {0.5,0.5}};
    std::vector<geometry::Point> expectedHull {{0,0}, {1,0}, {1,1}, {0,1}};
    auto hull = geometry::ConvexHull::compute(points);

    // Check if hull has correct number of points
    assert(hull.size() == 4);

    // Check if all expected points are in the hull
    for (const auto& p : expectedHull) {
        assert(std::find(hull.begin(), hull.end(), p) != hull.end());
    }

    // Test with random points
    for (int test = 0; test < 5; ++test) {
        auto randomPoints = testing::generateRandomPoints(50);
        auto randomHull = geometry::ConvexHull::compute(randomPoints);

        // Verify properties of convex hull
        // 1. All original points should be inside or on the hull
        for (const auto& p : randomPoints) {
            assert(testing::isPointInPolygon(p, randomHull) || 
                   std::find(randomHull.begin(), randomHull.end(), p) != randomHull.end());
        }

        // 2. Hull should be convex (all interior angles < 180°)
        for (size_t i = 0; i < randomHull.size(); ++i) {
            const auto& p1 = randomHull[i];
            const auto& p2 = randomHull[(i+1) % randomHull.size()];
            const auto& p3 = randomHull[(i+2) % randomHull.size()];

            // Check if turn is counter-clockwise
            double cross = (p2 - p1).cross(p3 - p2);
            assert(cross >= -1e-9);  // Allow for numerical precision issues
        }
    }

    std::cout << "ConvexHull tests passed!" << std::endl;
}

// Test DelaunayTriangulation
void testDelaunayTriangulation() {
    std::cout << "Testing DelaunayTriangulation..." << std::endl;

    // Test with simple square
    std::vector<geometry::Point> points {{0,0}, {1,0}, {0,1}, {1,1}};
    auto triangulation = geometry::DelaunayTriangulation::compute(points);

    // Should have 2 triangles for a square
    assert(triangulation.size() == 2);

    // Test with random points
    for (int test = 0; test < 5; ++test) {
        auto randomPoints = testing::generateRandomPoints(20);
        auto triangles = geometry::DelaunayTriangulation::compute(randomPoints);

        // Basic checks for Delaunay property (would need more comprehensive tests)
        assert(!triangles.empty());

        // Check if triangulation covers all points
        std::set<geometry::Point> uniquePoints;
        for (const auto& triangle : triangles) {
            geometry::Point a, b, c;
            std::tie(a, b, c) = triangle;
            uniquePoints.insert(a);
            uniquePoints.insert(b);
            uniquePoints.insert(c);
        }

        // All input points should be in the triangulation
        for (const auto& p : randomPoints) {
            bool found = false;
            for (const auto& vertex : uniquePoints) {
                if (vertex == p) {
                    found = true;
                    break;
                }
            }
            assert(found);
        }
    }

    std::cout << "DelaunayTriangulation tests passed!" << std::endl;
}

// Test VoronoiDiagram
void testVoronoiDiagram() {
    std::cout << "Testing VoronoiDiagram..." << std::endl;

    // Test with triangle
    std::vector<geometry::Point> points {{0,0}, {2,0}, {1,1.732}};
    auto cells = geometry::VoronoiDiagram::compute(points);

    // Should have 3 cells for 3 points
    assert(cells.size() == 3);

    // Test with random points
    for (int test = 0; test < 5; ++test) {
        auto randomPoints = testing::generateRandomPoints(10);
        auto voronoiCells = geometry::VoronoiDiagram::compute(randomPoints);

        // Basic check - number of cells should match number of input points
        assert(voronoiCells.size() == randomPoints.size());

        // Additional checks could be implemented for Voronoi properties
    }

    std::cout << "VoronoiDiagram tests passed!" << std::endl;
}

int main() {
    testConvexHull();
    testDelaunayTriangulation();
    testVoronoiDiagram();
    std::cout << "All tests passed successfully!" << std::endl;
    return 0;
}

#include <atomic>
#include <vector>
#include <thread>
#include <iostream>
#include <chrono>
#include <map>
#include <pthread.h>

// Using moodycamel's ConcurrentQueue
#include "concurrentqueue.h"

class Order {
public:
    enum class Type { BUY, SELL };

    Order(Type type = Type::BUY, const std::string& symbol = "", double price = 0.0, unsigned int quantity = 0)
        : type(type), symbol(symbol), price(price), quantity(quantity) {}

    Type type;
    std::string symbol;
    double price;
    unsigned int quantity;
};

class OrderBook {
public:
    void addOrder(const Order& order) {
        auto& orders = (order.type == Order::Type::BUY) ? buyOrders : sellOrders;
        auto it = orders.find(order.price);
        if (it == orders.end()) {
            orders[order.price] = {order};
        } else {
            it->second.push_back(order);
        }
    }

    void matchOrders() {
        for (auto buy_it = buyOrders.rbegin(); buy_it != buyOrders.rend(); ++buy_it) {
            auto sell_it = sellOrders.begin();
            while (sell_it != sellOrders.end() && buy_it->first >= sell_it->first) {
                auto& buy_list = buy_it->second;
                auto& sell_list = sell_it->second;

                buy_list.pop_back();
                sell_list.pop_back();

                if (buy_list.empty()) {
                    buyOrders.erase(--buy_it.base());
                }
                if (sell_list.empty()) {
                    sellOrders.erase(sell_it++);
                } else {
                    ++sell_it;
                }
            }
        }
    }

private:
    std::map<double, std::vector<Order>, std::greater<>> buyOrders;
    std::map<double, std::vector<Order>> sellOrders;
};

class MatchingEngine {
public:
    MatchingEngine() {
        // Set CPU affinity
        cpu_set_t cpuset;
        CPU_ZERO(&cpuset);
        CPU_SET(0, &cpuset);
        pthread_setaffinity_np(pthread_self(), sizeof(cpu_set_t), &cpuset);

        // Start matching thread
        matchingThread = std::thread([this] { run(); });
    }

    ~MatchingEngine() {
        running = false;
        matchingThread.join();
    }

    void submitOrder(const Order& order) {
        while (!orderQueue.enqueue(order))
            ; // Spin if queue is full
    }

private:
    void run() {
        Order order;
        while (running) {
            while (orderQueue.try_dequeue(order)) {
                orderBook.addOrder(order);
            }
            orderBook.matchOrders();
        }
    }

    std::atomic<bool> running{true};
    moodycamel::ConcurrentQueue<Order> orderQueue{10000};
    OrderBook orderBook;
    std::thread matchingThread;
};

void simulateMarketLoad(MatchingEngine& engine) {
    std::vector<std::thread> traders;
    for (int i = 0; i < 10; ++i) {
        traders.emplace_back([&engine]() {
            for (int j = 0; j < 1000; ++j) {
                engine.submitOrder(Order(Order::Type::BUY, "AAPL", 150 + (rand() % 10), 10));
                engine.submitOrder(Order(Order::Type::SELL, "AAPL", 150 - (rand() % 10), 10));
            }
        });
    }

    for (auto& trader : traders) {
        trader.join();
    }
}

int main() {
    MatchingEngine engine;

    auto start = std::chrono::high_resolution_clock::now();
    simulateMarketLoad(engine);
    auto end = std::chrono::high_resolution_clock::now();

    std::cout << "Simulation time: " << 
        std::chrono::duration_cast<std::chrono::microseconds>(end - start).count() << 
        " microseconds\n";

    return 0;
}

