// PaymentController.java
package com.paymentapi.controller;

import com.paymentapi.model.CreditCard;
import com.paymentapi.model.TokenResponse;
import com.paymentapi.service.PaymentService;
import com.paymentapi.service.WebhookService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import javax.servlet.http.HttpServletRequest;
import javax.validation.Valid;
import java.util.Map;

@RestController
@RequestMapping("/api/v1")
public class PaymentController {

    @Autowired
    private PaymentService paymentService;

    @Autowired
    private WebhookService webhookService;

    @PostMapping("/tokenize")
    public ResponseEntity<TokenResponse> tokenizeCard(
            @Valid @RequestBody CreditCard creditCard,
            HttpServletRequest request) {

        // Enforce TLS
        if (!request.isSecure()) {
            return ResponseEntity.badRequest().build();
        }

        TokenResponse response = paymentService.tokenizeCard(creditCard);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/webhook")
    public ResponseEntity<String> handleWebhook(
            @RequestBody Map<String, Object> payload,
            @RequestHeader("X-Signature") String signature,
            @RequestHeader("X-Timestamp") String timestamp,
            HttpServletRequest request) {

        // Enforce TLS
        if (!request.isSecure()) {
            return ResponseEntity.badRequest().build();
        }

        if (webhookService.validateWebhook(payload, signature, timestamp)) {
            return ResponseEntity.ok("Webhook processed successfully");
        } else {
            return ResponseEntity.badRequest().body("Invalid webhook signature or expired request");
        }
    }
}

