package com.paymentapi.service;

import com.paymentapi.model.CreditCard;
import com.paymentapi.model.TokenResponse;
import org.springframework.stereotype.Service;

import java.security.SecureRandom;
import java.util.Base64;

@Service
public class PaymentService {

    private final SecureRandom secureRandom = new SecureRandom();

    public TokenResponse tokenizeCard(CreditCard creditCard) {
        try {
            // Validate card number using Luhn algorithm
            if (!isValidCardNumber(creditCard.getNumber())) {
                return new TokenResponse(null, null, null, false, "Invalid card number");
            }

            // Generate secure token (in production, use external PCI-compliant tokenization service)
            String token = generateSecureToken();

            // Extract last 4 digits for display
            String last4 = creditCard.getNumber().substring(creditCard.getNumber().length() - 4);

            // Determine card type
            String cardType = determineCardType(creditCard.getNumber());

            // NEVER store raw PAN - only return token and safe data
            return new TokenResponse(token, last4, cardType, true, "Card tokenized successfully");

        } catch (Exception e) {
            return new TokenResponse(null, null, null, false, "Tokenization failed");
        }
    }

    private String generateSecureToken() {
        byte[] tokenBytes = new byte[32];
        secureRandom.nextBytes(tokenBytes);
        return "tok_" + Base64.getUrlEncoder().withoutPadding().encodeToString(tokenBytes);
    }

    private boolean isValidCardNumber(String cardNumber) {
        // Luhn algorithm implementation
        int sum = 0;
        boolean alternate = false;

        for (int i = cardNumber.length() - 1; i >= 0; i--) {
            int n = Integer.parseInt(cardNumber.substring(i, i + 1));
            if (alternate) {
                n *= 2;
                if (n > 9) {
                    n = (n % 10) + 1;
                }
            }
            sum += n;
            alternate = !alternate;
        }

        return (sum % 10 == 0);
    }

    private String determineCardType(String cardNumber) {
        if (cardNumber.matches("^4[0-9]{12}(?:[0-9]{3})?$")) {
            return "VISA";
        } else if (cardNumber.matches("^5[1-5][0-9]{14}$")) {
            return "MASTERCARD";
        } else if (cardNumber.matches("^3[47][0-9]{13}$")) {
            return "AMEX";
        } else {
            return "UNKNOWN";
        }
    }
}

// WebhookService.java
package com.paymentapi.service;

import com.fasterxml.jackson.databind.ObjectMapper;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.nio.charset.StandardCharsets;
import java.time.Instant;
import java.util.Base64;
import java.util.Map;
import java.util.Set;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class WebhookService {

    private static final String HMAC_SHA256 = "HmacSHA256";
    private static final long WEBHOOK_TIMEOUT_SECONDS = 300; // 5 minutes

    @Value("${webhook.secret:default-webhook-secret}")
    private String webhookSecret;

    private final ObjectMapper objectMapper = new ObjectMapper();
    private final Set<String> processedWebhooks = ConcurrentHashMap.newKeySet();

    public boolean validateWebhook(Map<String, Object> payload, String signature, String timestamp) {
        try {
            // Check if timestamp is valid
            if (!isValidTimestamp(timestamp)) {
                return false;
            }

            // Create signature payload
            String payloadString = objectMapper.writeValueAsString(payload);
            String signaturePayload = timestamp + "." + payloadString;

            // Validate HMAC signature
            if (!validateHmacSignature(signaturePayload, signature)) {
                return false;
            }

            // Check for replay attacks using unique webhook identifier
            String webhookId = timestamp + "_" + payloadString.hashCode();
            if (processedWebhooks.contains(webhookId)) {
                return false; // Duplicate webhook
            }

            // Add to processed webhooks to prevent replay
            processedWebhooks.add(webhookId);

            // Process the webhook...

            return true;

        } catch (Exception e) {
            return false;
        }
    }

    private boolean isValidTimestamp(String timestamp) {
        try {
            long webhookTime = Long.parseLong(timestamp);
            long currentTime = Instant.now().getEpochSecond();
            return Math.abs(currentTime - webhookTime) <= WEBHOOK_TIMEOUT_SECONDS;
        } catch (NumberFormatException e) {
            return false;
        }
    }

    private boolean validateHmacSignature(String data, String clientSignature) {
        try {
            Mac sha256Hmac = Mac.getInstance(HMAC_SHA256);
            SecretKeySpec secretKey = new SecretKeySpec(
                webhookSecret.getBytes(StandardCharsets.UTF_8), 
                HMAC_SHA256
            );
            sha256Hmac.init(secretKey);

            byte[] signedData = sha256Hmac.doFinal(data.getBytes(StandardCharsets.UTF_8));
            String computedSignature = Base64.getEncoder().encodeToString(signedData);

            return computedSignature.equals(clientSignature);

        } catch (Exception e) {
            return false;
        }
    }
}

