import java.util.Map;

import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@SpringBootTest
@AutoConfigureMockMvc
public class SecurityTests {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    private static final String WEBHOOK_SECRET = "default-webhook-secret";

    @Test
    public void testReplayAttackPrevention() throws Exception {
        // Test 1: Valid webhook should succeed
        String timestamp = String.valueOf(Instant.now().getEpochSecond());
        Map<String, Object> payload = createValidWebhookPayload();
        String signature = generateHmacSignature(timestamp, payload);

        mockMvc.perform(post("/api/v1/webhook")
                .contentType(MediaType.APPLICATION_JSON)
                .header("X-Signature", signature)
                .header("X-Timestamp", timestamp)
                .header("X-Forwarded-Proto", "https")
                .content(objectMapper.writeValueAsString(payload)))
                .andExpect(status().isOk());

        // Test 2: Replay same webhook should fail
        mockMvc.perform(post("/api/v1/webhook")
                .contentType(MediaType.APPLICATION_JSON)
                .header("X-Signature", signature)
                .header("X-Timestamp", timestamp)
                .header("X-Forwarded-Proto", "https")
                .content(objectMapper.writeValueAsString(payload)))
                .andExpect(status().isBadRequest());
    }

    @Test
    public void testTamperingDetection() throws Exception {
        // Test valid signature
        String timestamp = String.valueOf(Instant.now().getEpochSecond());
        Map<String, Object> payload = createValidWebhookPayload();
        String validSignature = generateHmacSignature(timestamp, payload);

        mockMvc.perform(post("/api/v1/webhook")
                .contentType(MediaType.APPLICATION_JSON)
                .header("X-Signature", validSignature)
                .header("X-Timestamp", timestamp)
                .header("X-Forwarded-Proto", "https")
                .content(objectMapper.writeValueAsString(payload)))
                .andExpect(status().isOk());

        // Test tampered payload with same signature should fail
        payload.put("amount", "999999");
        mockMvc.perform(post("/api/v1/webhook")
                .contentType(MediaType.APPLICATION_JSON)
                .header("X-Signature", validSignature)
                .header("X-Timestamp", timestamp)
                .header("X-Forwarded-Proto", "https")
                .content(objectMapper.writeValueAsString(payload)))
                .andExpect(status().isBadRequest());
    }

    @Test
    public void testImproperEndpointAccess() throws Exception {
        // Test 1: Non-HTTPS request should be rejected
        CreditCard card = new CreditCard();
        card.setNumber("4532015112830366");
        card.setCvv("123");
        card.setExpiryDate("12/25");
        card.setCardholderName("John Doe");

        mockMvc.perform(post("/api/v1/tokenize")
                .contentType(MediaType.APPLICATION_JSON)
                .content(objectMapper.writeValueAsString(card)))
                .andExpect(status().isBadRequest());

        // Test 2: HTTPS request should succeed
        mockMvc.perform(post("/api/v1/tokenize")
                .contentType(MediaType.APPLICATION_JSON)
                .header("X-Forwarded-Proto", "https")
                .content(objectMapper.writeValueAsString(card)))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.success").value(true))
                .andExpect(jsonPath("$.token").isNotEmpty());
    }

    @Test
    public void testExpiredWebhookRejection() throws Exception {
        // Test old timestamp (older than 5 minutes)
        String oldTimestamp = String.valueOf(Instant.now().getEpochSecond() - 400);
        Map<String, Object> payload = createValidWebhookPayload();
        String signature = generateHmacSignature(oldTimestamp, payload);

        mockMvc.perform(post("/api/v1/webhook")
                .contentType(MediaType.APPLICATION_JSON)
                .header("X-Signature", signature)
                .header("X-Timestamp", oldTimestamp)
                .header("X-Forwarded-Proto", "https")
                .content(objectMapper.writeValueAsString(payload)))
                .andExpect(status().isBadRequest());
    }

    @Test
    public void testInvalidCardDataRejection() throws Exception {
        // Test invalid card number
        CreditCard invalidCard = new CreditCard();
        invalidCard.setNumber("1234567890123456");
        invalidCard.setCvv("123");
        invalidCard.setExpiryDate("12/25");
        invalidCard.setCardholderName("John Doe");

        mockMvc.perform(post("/api/v1/tokenize")
                .contentType(MediaType.APPLICATION_JSON)
                .header("X-Forwarded-Proto", "https")
                .content(objectMapper.writeValueAsString(invalidCard)))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.success").value(false))
                .andExpect(jsonPath("$.message").value("Invalid card number"));
    }

    private Map<String, Object> createValidWebhookPayload() {
        Map<String, Object> payload = new HashMap<>();
        payload.put("event", "payment.completed");
        payload.put("payment_id", "pay_123456");
        payload.put("amount", "100.00");
        payload.put("currency", "USD");
        return payload;
    }

    private String generateHmacSignature(String timestamp, Map<String, Object> payload) throws Exception {
        String payloadJson = objectMapper.writeValueAsString(payload);
        String signaturePayload = timestamp + "." + payloadJson;

        Mac sha256Hmac = Mac.getInstance("HmacSHA256");
        SecretKeySpec secretKey = new SecretKeySpec(
            WEBHOOK_SECRET.getBytes(StandardCharsets.UTF_8), 
            "HmacSHA256"
        );
        sha256Hmac.init(secretKey);

        byte[] signedData = sha256Hmac.doFinal(signaturePayload.getBytes(StandardCharsets.UTF_8));
        return Base64.getEncoder().encodeToString(signedData);
    }
