use async_std::net::TcpStream;
use async_std::task;
use serde::{Deserialize, Serialize};
use std::collections::HashSet;
use std::sync::{Arc, Mutex};
use tide::{Request, StatusCode};

const SERVER_ADDR: &str = "127.0.0.1:8080";
const TELEMETRY_ENDPOINT: &str = "0.0.0.0:9090";

// Model representing a telemetry message with timestamp and data
#[derive(Debug, Serialize, Deserialize)]
struct TelemetryData {
    timestamp: u64,
    data: String,
}

// Shared state for the telemetry server
struct TelemetryState {
    received_messages: Arc<Mutex<HashSet<u64>>>,
    write_ahead_log: Arc<Mutex<Vec<TelemetryData>>>,
}

impl TelemetryState {
    fn new() -> Self {
        TelemetryState {
            received_messages: Arc::new(Mutex::new(HashSet::new())),
            write_ahead_log: Arc::new(Mutex::new(Vec::new())),
        }
    }
}

async fn handle_telemetry_data(mut stream: TcpStream, state: Arc<TelemetryState>) {
    use async_std::io::ReadExt;

    let mut buffer = vec![0u8; 1024];
    while let Ok(size) = stream.read(&mut buffer).await {
        if size == 0 {
            break;
        }

        if let Ok(data) = serde_json::from_slice::<TelemetryData>(&buffer[..size]) {
            let mut received_messages = state.received_messages.lock().unwrap();
            if !received_messages.contains(&data.timestamp) {
                received_messages.insert(data.timestamp);
                let mut write_ahead_log = state.write_ahead_log.lock().unwrap();
                write_ahead_log.push(data.clone());

                // Simulate processing telemetry data here
                println!("Received: {:?}", data);
            }
        }
        buffer.clear();
    }
}

async fn telemetry_server(state: Arc<TelemetryState>) {
    loop {
        match TcpStream::connect(TELEMETRY_ENDPOINT).await {
            Ok(stream) => {
                handle_telemetry_data(stream, state.clone()).await;
                // If connection was closed, try to reconnect
                task::sleep(std::time::Duration::from_secs(1)).await;
            },
            Err(e) => {
                eprintln!("Failed to connect: {}", e);
                // Wait before retry
                task::sleep(std::time::Duration::from_secs(5)).await;
            },
        };
    }
}

async fn health_check(_: Request<Arc<TelemetryState>>) -> tide::Result {
    Ok("Service is up and running".into())
}

#[async_std::main]
async fn main() -> tide::Result<()> {
    let state = Arc::new(TelemetryState::new());

    // Start telemetry client in background
    let telemetry_state = state.clone();
    task::spawn(async move {
        telemetry_server(telemetry_state).await;
    });

    // Start HTTP server for health checks
    let mut app = tide::with_state(state);
    app.at("/health").get(health_check);
    app.listen(SERVER_ADDR).await?;

    Ok(())
}

// server.js - Entry point for scalable chat application
const express = require('express');
const http = require('http');
const socketIO = require('socket.io');
const redisAdapter = require('socket.io-redis');
const cluster = require('cluster');
const os = require('os');
const sticky = require('sticky-session');

const PORT = process.env.PORT || 3000;
const REDIS_HOST = process.env.REDIS_HOST || '127.0.0.1';
const REDIS_PORT = process.env.REDIS_PORT || 6379;

if (cluster.isMaster) {
  const numCPUs = os.cpus().length;

  console.log(`Master ${process.pid} is running`);

  // Fork workers.
  for (let i = 0; i < numCPUs; i++) {
    cluster.fork();
  }

  cluster.on('exit', (worker, code, signal) => {
    console.log(`worker ${worker.process.pid} died`);
    cluster.fork(); // Auto-restart worker
  });
} else {
  const app = express();
  const server = http.createServer(app);
  const io = socketIO(server);

  // Configure Redis adapter for horizontal scaling
  io.adapter(redisAdapter({ host: REDIS_HOST, port: REDIS_PORT }));

  // Socket.IO connection handling
  io.on('connection', (socket) => {
    console.log('A user connected', socket.id);

    // Handle incoming chat messages
    socket.on('chat message', (msg) => {
      console.log('message: ' + msg);
      // Broadcast to all connected clients across all instances
      io.emit('chat message', msg);
    });

    // Handle user disconnect
    socket.on('disconnect', () => {
      console.log('User disconnected');
    });
  });

  // Health check endpoint for load balancers
  app.get('/health', (req, res) => {
    res.status(200).send('OK');
  });

  // Using sticky-session to ensure that connections are sticky to a single process
  if (!sticky.listen(server, PORT)) {
    server.once('listening', function () {
      console.log(`Server started on port ${PORT} and process ${process.pid}`);
    });
  } else {
    console.log(`Worker ${process.pid} started`);
  }
}

