import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { BehaviorSubject, Observable, of } from 'rxjs';
import { catchError, delay, tap } from 'rxjs/operators';
import { MatSnackBar } from '@angular/material/snack-bar';
import { Widget } from '../models/widget.model';

@Injectable({
  providedIn: 'root'
})
export class ConnectivityService {
  private isOfflineSubject = new BehaviorSubject<boolean>(false);
  isOffline$ = this.isOfflineSubject.asObservable();

  private isLoadingSubject = new BehaviorSubject<boolean>(false);
  isLoading$ = this.isLoadingSubject.asObservable();

  private layoutKey = 'financial-dashboard-layout';

  constructor(private http: HttpClient, private snackBar: MatSnackBar) {
    window.addEventListener('online', () => this.updateOnlineStatus());
    window.addEventListener('offline', () => this.updateOnlineStatus());
    this.updateOnlineStatus();
  }

  private updateOnlineStatus() {
    this.isOfflineSubject.next(!navigator.onLine);

    if (!navigator.onLine) {
      this.snackBar.open('You are offline. Some features may be limited.', 'Dismiss', {
        duration: 5000
      });
    }
  }

  fetchFinancialData(widgetId: number): Observable<number[]> {
    this.isLoadingSubject.next(true);

    // Simulate API call with potential network delay
    return this.http.get<number[]>(`/api/financial-data/${widgetId}`).pipe(
      delay(Math.random() * 2000), // Simulate network latency
      tap(() => this.isLoadingSubject.next(false)),
      catchError(error => {
        this.isLoadingSubject.next(false);
        if (!navigator.onLine) {
          return of([10, 15, 8, 12, 20, 18]); // Fallback data when offline
        }
        console.error('Error fetching data:', error);
        return of([]);
      })
    );
  }

  saveLayout(widgets?: Widget[]) {
    if (this.isOfflineSubject.value) {
      this.snackBar.open('Cannot save layout while offline', 'Dismiss', {
        duration: 3000
      });
      return;
    }

    if (widgets) {
      localStorage.setItem(this.layoutKey, JSON.stringify(widgets));
    }

    this.snackBar.open('Dashboard layout saved successfully', 'Dismiss', {
      duration: 3000
    });
  }

  loadLayout(): Widget[] | null {
    const savedLayout = localStorage.getItem(this.layoutKey);
    return savedLayout ? JSON.parse(savedLayout) : null;
  }

  resetLayout() {
    this.snackBar.open('Dashboard layout has been reset', 'Dismiss', {
      duration: 3000
    });
    localStorage.removeItem(this.layoutKey);
  }
}

